import React from 'react';
import { IPAFeature, IPACardData } from '../types';
import { Volume2, CheckCircle, XCircle } from 'lucide-react';
import { playIPASound } from '../services/geminiService';

interface FlashcardProps {
  data: IPACardData;
  features: IPAFeature[];
  isFlipped: boolean;
  onFlip: () => void;
  isQuiz: boolean;
  userInput: string;
  setUserInput: (val: string) => void;
  feedback: 'none' | 'correct' | 'incorrect';
  onSubmit: (val: string) => void;
}

const FeatureContent: React.FC<{ feature: IPAFeature; data: IPACardData; isHidden?: boolean }> = ({ feature, data, isHidden }) => {
  if (isHidden) return <div className="text-gray-300 italic">Hidden for Quiz</div>;

  switch (feature) {
    case IPAFeature.SYMBOL:
      return <div className="ipa-font text-8xl font-bold text-indigo-900">{data.symbol}</div>;
    case IPAFeature.LABEL:
      return <div className="text-2xl font-semibold text-slate-700 text-center px-4">{data.label}</div>;
    case IPAFeature.WORDS:
      return (
        <div className="flex flex-col items-center gap-2">
          <span className="text-sm uppercase tracking-widest text-slate-400 mb-2">Examples</span>
          {data.words.map((w, i) => (
            <span key={i} className="text-xl font-medium text-slate-700">{w}</span>
          ))}
        </div>
      );
    case IPAFeature.SOUND:
      return (
        <button 
          onClick={(e) => { e.stopPropagation(); playIPASound(data.audioPrompts[Math.floor(Math.random() * data.audioPrompts.length)]); }}
          className="p-8 bg-indigo-50 rounded-full hover:bg-indigo-100 transition-colors group"
        >
          <Volume2 className="w-16 h-16 text-indigo-600 group-hover:scale-110 transition-transform" />
        </button>
      );
    default:
      return null;
  }
};

export const Flashcard: React.FC<FlashcardProps> = ({ 
  data, features, isFlipped, onFlip, isQuiz, userInput, setUserInput, feedback, onSubmit 
}) => {
  const frontFeature = features[0];
  const backFeature = features[1];

  const handleQuizSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSubmit(userInput);
  };

  return (
    <div className="w-full max-w-sm h-96 perspective-1000 cursor-pointer" onClick={onFlip}>
      <div className={`relative w-full h-full transition-transform duration-700 preserve-3d ${isFlipped ? 'rotate-y-180' : ''}`}>

        {/* Front */}
        <div className="absolute inset-0 bg-white rounded-3xl shadow-xl flex items-center justify-center border-2 border-slate-100 backface-hidden">
          <FeatureContent feature={frontFeature} data={data} />
          <div className="absolute bottom-4 right-6 text-slate-300 text-sm font-bold">FRONT</div>
        </div>

        {/* Back */}
        <div className="absolute inset-0 bg-white rounded-3xl shadow-xl flex flex-col items-center justify-center border-2 border-slate-100 backface-hidden rotate-y-180">
          {isQuiz && !isFlipped ? (
            <div className="p-6 w-full flex flex-col items-center gap-4" onClick={(e) => e.stopPropagation()}>
              <h3 className="text-lg font-bold text-slate-800">Identify the {backFeature.toLowerCase()}</h3>
              <form onSubmit={handleQuizSubmit} className="w-full">
                <input
                  autoFocus
                  type="text"
                  value={userInput}
                  onChange={(e) => setUserInput(e.target.value)}
                  className="w-full px-4 py-3 rounded-xl border-2 border-slate-200 focus:border-indigo-500 outline-none text-center text-xl font-bold"
                  placeholder="Type here..."
                />
                <button 
                  type="submit"
                  className="w-full mt-4 bg-indigo-600 text-white py-3 rounded-xl font-bold hover:bg-indigo-700 transition-colors"
                >
                  CHECK
                </button>
              </form>
            </div>
          ) : (
            <>
              {feedback === 'correct' && <CheckCircle className="text-green-500 w-12 h-12 mb-4" />}
              {feedback === 'incorrect' && <XCircle className="text-red-500 w-12 h-12 mb-4" />}
              <FeatureContent feature={backFeature} data={data} />
            </>
          )}
          <div className="absolute bottom-4 right-6 text-slate-300 text-sm font-bold">BACK</div>
        </div>

      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { IPAFeature, IPACardData } from '../types';
import { Volume2, ChevronRight, ChevronLeft } from 'lucide-react';
