interface FoldedCardProps {
  data: IPACardData;
  features: IPAFeature[];
}

const FeatureIcon: React.FC<{ feature: IPAFeature }> = ({ feature }) => {
  switch (feature) {
    case IPAFeature.SYMBOL: return <span className="text-lg font-bold">Ω</span>;
    case IPAFeature.LABEL: return <span className="text-lg font-bold">abc</span>;
    case IPAFeature.WORDS: return <span className="text-lg font-bold">""</span>;
    case IPAFeature.SOUND: return <Volume2 className="w-5 h-5" />;
    default: return null;
  }
};

const FeatureDisplay: React.FC<{ feature: IPAFeature; data: IPACardData }> = ({ feature, data }) => {
  switch (feature) {
    case IPAFeature.SYMBOL:
      return <div className="ipa-font text-7xl font-bold text-indigo-900">{data.symbol}</div>;
    case IPAFeature.LABEL:
      return <div className="text-xl font-semibold text-slate-700 text-center px-4 leading-relaxed">{data.label}</div>;
    case IPAFeature.WORDS:
      return (
        <div className="flex flex-wrap justify-center gap-3">
          {data.words.map((w, i) => (
            <span key={i} className="px-4 py-2 bg-slate-100 rounded-full text-slate-700 font-medium">{w}</span>
          ))}
        </div>
      );
    case IPAFeature.SOUND:
      return (
        <button 
          onClick={() => playIPASound(data.audioPrompts[0])}
          className="p-6 bg-indigo-600 rounded-full text-white shadow-lg hover:bg-indigo-700 transition-all active:scale-95"
        >
          <Volume2 className="w-10 h-10" />
        </button>
      );
    default:
      return null;
  }
};

export const FoldedCard: React.FC<FoldedCardProps> = ({ data, features }) => {
  const [activeSurface, setActiveSurface] = useState(0);

  const nextSurface = () => setActiveSurface((s) => (s + 1) % features.length);
  const prevSurface = () => setActiveSurface((s) => (s - 1 + features.length) % features.length);

  return (
    <div className="w-full max-w-sm h-96 relative flex items-center justify-center bg-white rounded-3xl shadow-2xl border border-slate-100 overflow-hidden">
      {/* Background Paper Fold Effect */}
      <div className="absolute top-0 right-0 w-16 h-16 bg-slate-100 -rotate-45 translate-x-8 -translate-y-8 shadow-inner"></div>

      {/* Navigation Dots / Indicator */}
      <div className="absolute top-6 left-1/2 -translate-x-1/2 flex gap-2">
        {features.map((_, i) => (
          <div 
            key={i} 
            className={`h-2 rounded-full transition-all duration-300 ${i === activeSurface ? 'w-8 bg-indigo-500' : 'w-2 bg-slate-200'}`}
          />
        ))}
      </div>

      {/* Main Content Area */}
      <div className="flex flex-col items-center justify-center p-8 text-center animate-in fade-in zoom-in duration-300" key={activeSurface}>
        <div className="text-xs font-bold text-slate-300 uppercase tracking-widest mb-6 flex items-center gap-2">
          <FeatureIcon feature={features[activeSurface]} />
          {features[activeSurface]}
        </div>
        <FeatureDisplay feature={features[activeSurface]} data={data} />
      </div>

      {/* Surface Switching Controls */}
      <button 
        onClick={prevSurface}
        className="absolute left-2 top-1/2 -translate-y-1/2 p-2 rounded-full bg-slate-50 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 transition-colors"
      >
        <ChevronLeft className="w-8 h-8" />
      </button>
      <button 
        onClick={nextSurface}
        className="absolute right-2 top-1/2 -translate-y-1/2 p-2 rounded-full bg-slate-50 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 transition-colors"
      >
        <ChevronRight className="w-8 h-8" />
      </button>

      {/* Folded Tab Markers at the bottom */}
      <div className="absolute bottom-0 inset-x-0 h-12 flex">
        {features.map((feature, i) => (
          <button
            key={i}
            onClick={() => setActiveSurface(i)}
            className={`flex-1 flex items-center justify-center border-t transition-all ${
              i === activeSurface 
                ? 'bg-indigo-50 text-indigo-600 border-indigo-200 font-bold' 
                : 'bg-slate-50 text-slate-400 border-slate-100'
            }`}
          >
            <FeatureIcon feature={feature} />
          </button>
        ))}
      </div>
    </div>
  );
};

import React from 'react';
import { IPAFeature, AppSettings, StudyMode } from '../types';
import { X, Check } from 'lucide-react';

interface SettingsOverlayProps {
  settings: AppSettings;
  onUpdate: (settings: AppSettings) => void;
  onClose: () => void;
}

export const SettingsOverlay: React.FC<SettingsOverlayProps> = ({ settings, onUpdate, onClose }) => {
  const toggleFeature = (feature: IPAFeature) => {
    let newFeatures = [...settings.activeFeatures];
    if (newFeatures.includes(feature)) {
      if (newFeatures.length > 2) {
        newFeatures = newFeatures.filter(f => f !== feature);
      }
    } else {
      newFeatures.push(feature);
    }
    onUpdate({ ...settings, activeFeatures: newFeatures });
  };

  const setMode = (mode: StudyMode) => {
    onUpdate({ ...settings, mode });
  };

  return (
    <div className="fixed inset-0 bg-slate-900/50 backdrop-blur-sm z-50 flex items-end sm:items-center justify-center p-4">
      <div className="bg-white w-full max-w-md rounded-3xl p-8 shadow-2xl animate-in slide-in-from-bottom duration-300">
        <div className="flex justify-between items-center mb-8">
          <h2 className="text-2xl font-bold text-slate-800">Study Config</h2>
          <button onClick={onClose} className="p-2 bg-slate-100 rounded-full hover:bg-slate-200 transition-colors">
            <X className="w-6 h-6 text-slate-600" />
          </button>
        </div>

        <div className="space-y-8">
          <section>
            <h3 className="text-sm font-bold text-slate-400 uppercase tracking-widest mb-4">Study Mode</h3>
            <div className="grid grid-cols-2 gap-4">
              {(['FLASHCARD', 'QUIZ'] as StudyMode[]).map((m) => (
                <button
                  key={m}
                  onClick={() => setMode(m)}
                  className={`py-3 rounded-2xl font-bold transition-all border-2 ${
                    settings.mode === m 
                      ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg' 
                      : 'bg-white border-slate-200 text-slate-600 hover:border-slate-300'
                  }`}
                >
                  {m}
                </button>
              ))}
            </div>
          </section>

          <section>
            <h3 className="text-sm font-bold text-slate-400 uppercase tracking-widest mb-4">Visible Features</h3>
            <p className="text-xs text-slate-400 mb-4">Select at least 2 features to build your cards.</p>
            <div className="space-y-3">
              {Object.values(IPAFeature).map((feature) => {
                const isActive = settings.activeFeatures.includes(feature);
                return (
                  <button
                    key={feature}
                    onClick={() => toggleFeature(feature)}
                    className={`w-full flex items-center justify-between p-4 rounded-2xl border-2 transition-all ${
                      isActive ? 'bg-indigo-50 border-indigo-200' : 'bg-white border-slate-100'
                    }`}
                  >
                    <span className={`font-bold ${isActive ? 'text-indigo-700' : 'text-slate-500'}`}>
                      {feature}
                    </span>
                    {isActive && <div className="bg-indigo-600 p-1 rounded-full"><Check className="w-4 h-4 text-white" /></div>}
                  </button>
                );
              })}
            </div>
          </section>

          <button 
            onClick={onClose}
            className="w-full py-4 bg-slate-900 text-white rounded-2xl font-bold text-lg hover:bg-slate-800 transition-colors"
          >
            APPLY SETTINGS
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import { IPAFeature, IPACardData, AppSettings, CardState } from './types';
import { ipaDataset } from './data/ipaData';
import { Flashcard } from './components/Flashcard';
import { FoldedCard } from './components/FoldedCard';
import { SettingsOverlay } from './components/SettingsOverlay';
import { Settings, RefreshCw, Layers, Microscope, Music } from 'lucide-react';
import { synthesizeIPAWord } from './services/geminiService';

const App: React.FC = () => {
  const [settings, setSettings] = useState<AppSettings>({
    activeFeatures: [IPAFeature.SYMBOL, IPAFeature.LABEL],
    mode: 'FLASHCARD'
  });

  const [cardState, setCardState] = useState<CardState>({
    currentIndex: 0,
    isFlipped: false,
    currentSide: 0,
    userInput: '',
    feedback: 'none'
  });

  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [activeTab, setActiveTab] = useState<'study' | 'lab'>('study');
  const [labInput, setLabInput] = useState('');

  const currentCard = ipaDataset[cardState.currentIndex];

  const handleNext = useCallback(() => {
    setCardState(prev => ({
      ...prev,
      currentIndex: (prev.currentIndex + 1) % ipaDataset.length,
      isFlipped: false,
      userInput: '',
      feedback: 'none'
    }));
  }, []);

  const handlePrev = useCallback(() => {
    setCardState(prev => ({
      ...prev,
      currentIndex: (prev.currentIndex - 1 + ipaDataset.length) % ipaDataset.length,
      isFlipped: false,
      userInput: '',
      feedback: 'none'
    }));
  }, []);

  const handleFlip = () => {
    if (settings.activeFeatures.length === 2) {
      setCardState(prev => ({ ...prev, isFlipped: !prev.isFlipped }));
    }
  };

  const handleQuizSubmit = (input: string) => {
    const targetFeature = settings.activeFeatures[1];
    let isCorrect = false;

    if (targetFeature === IPAFeature.SYMBOL) isCorrect = input.toLowerCase().trim() === currentCard.symbol.toLowerCase();
    if (targetFeature === IPAFeature.LABEL) isCorrect = currentCard.label.toLowerCase().includes(input.toLowerCase().trim());
    if (targetFeature === IPAFeature.WORDS) isCorrect = currentCard.words.some(w => w.toLowerCase() === input.toLowerCase().trim());

    setCardState(prev => ({
      ...prev,
      feedback: isCorrect ? 'correct' : 'incorrect',
      isFlipped: true
    }));
  };

  const handleSynthesize = async () => {
    if (!labInput.trim()) return;
    await synthesizeIPAWord(labInput);
  };

  return (
    <div className="min-h-screen flex flex-col items-center justify-between pb-24 pt-8 px-4 max-w-md mx-auto relative">

      {/* Header */}
      <header className="w-full flex justify-between items-center mb-8">
        <div className="flex items-center gap-2">
          <div className="bg-indigo-600 p-2 rounded-xl text-white">
            <Layers className="w-6 h-6" />
          </div>
          <h1 className="text-xl font-black text-slate-800 tracking-tight">IPA MASTER</h1>
        </div>
        <button 
          onClick={() => setIsSettingsOpen(true)}
          className="p-3 bg-white rounded-2xl shadow-sm border border-slate-100 text-slate-400 hover:text-indigo-600 transition-colors"
        >
          <Settings className="w-6 h-6" />
        </button>
      </header>

      {/* Main Study Area */}
      {activeTab === 'study' ? (
        <main className="w-full flex-grow flex flex-col items-center justify-center gap-12">
          <div className="w-full flex justify-center h-96">
            {settings.activeFeatures.length === 2 ? (
              <Flashcard 
                data={currentCard}
                features={settings.activeFeatures}
                isFlipped={cardState.isFlipped}
                onFlip={handleFlip}
                isQuiz={settings.mode === 'QUIZ'}
                userInput={cardState.userInput}
                setUserInput={(v) => setCardState(p => ({ ...p, userInput: v }))}
                feedback={cardState.feedback}
                onSubmit={handleQuizSubmit}
              />
            ) : (
              <FoldedCard 
                data={currentCard}
                features={settings.activeFeatures}
              />
            )}
          </div>

          <div className="flex items-center gap-8">
            <button 
              onClick={handlePrev}
              className="p-4 bg-white rounded-3xl shadow-md border border-slate-100 hover:scale-105 transition-transform"
            >
              <RefreshCw className="w-6 h-6 text-slate-400 -scale-x-100" />
            </button>
            <div className="text-slate-400 font-bold text-lg">
              {cardState.currentIndex + 1} <span className="opacity-30">/</span> {ipaDataset.length}
            </div>
            <button 
              onClick={handleNext}
              className="p-4 bg-white rounded-3xl shadow-md border border-slate-100 hover:scale-105 transition-transform"
            >
              <RefreshCw className="w-6 h-6 text-slate-400" />
            </button>
          </div>
        </main>
      ) : (
        <main className="w-full flex-grow flex flex-col items-center justify-start py-8 gap-8">
          <div className="bg-indigo-50 p-8 rounded-[2.5rem] w-full border-2 border-dashed border-indigo-200">
            <div className="flex items-center gap-3 mb-6">
              <Microscope className="w-6 h-6 text-indigo-600" />
              <h2 className="text-xl font-bold text-indigo-900">IPA Lab</h2>
            </div>
            <p className="text-indigo-700/60 text-sm mb-6 leading-relaxed">
              Enter a sequence of IPA symbols and our AI will attempt to synthesize the phonetic sound for you.
            </p>
            <div className="bg-white p-4 rounded-3xl shadow-inner border-2 border-indigo-100 mb-6">
              <input 
                type="text"
                value={labInput}
                onChange={(e) => setLabInput(e.target.value)}
                placeholder="e.g. /æpl/"
                className="w-full bg-transparent text-3xl font-bold text-indigo-900 outline-none ipa-font placeholder:text-indigo-100"
              />
            </div>
            <button 
              onClick={handleSynthesize}
              disabled={!labInput.trim()}
