import React from 'react';
import { IPAFeature, AppSettings, StudyMode } from '../types';
import { X, Check, EyeOff } from 'lucide-react';

interface SettingsOverlayProps {
  settings: AppSettings;
  onUpdate: (settings: AppSettings) => void;
  onClose: () => void;
}

export const SettingsOverlay: React.FC<SettingsOverlayProps> = ({ settings, onUpdate, onClose }) => {
  const toggleFeature = (feature: IPAFeature) => {
    let newFeatures = [...settings.activeFeatures];
    if (newFeatures.includes(feature)) {
      if (newFeatures.length > 2) {
        newFeatures = newFeatures.filter(f => f !== feature);
      }
    } else {
      newFeatures.push(feature);
    }

    // Ensure masked feature is still in active features
    let newMasked = settings.maskedFeature;
    if (newMasked && !newFeatures.includes(newMasked)) {
      newMasked = newFeatures[1];
    }

    onUpdate({ ...settings, activeFeatures: newFeatures, maskedFeature: newMasked });
  };

  const setMode = (mode: StudyMode) => {
    onUpdate({ 
      ...settings, 
      mode, 
      maskedFeature: settings.maskedFeature || settings.activeFeatures[1] 
    });
  };

  const selectMasked = (feature: IPAFeature) => {
    onUpdate({ ...settings, maskedFeature: feature });
  };

  return (
    <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-50 flex items-end sm:items-center justify-center p-4">
      <div className="bg-white w-full max-w-md rounded-[2.5rem] p-8 shadow-2xl animate-in slide-in-from-bottom duration-300 max-h-[90vh] overflow-y-auto">
        <div className="flex justify-between items-center mb-8">
          <h2 className="text-2xl font-black text-slate-800 tracking-tight">STUDY SETUP</h2>
          <button onClick={onClose} className="p-2 bg-slate-100 rounded-full hover:bg-slate-200 transition-colors">
            <X className="w-6 h-6 text-slate-600" />
          </button>
        </div>

        <div className="space-y-8">
          <section>
            <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-4">Study Mode</h3>
            <div className="grid grid-cols-2 gap-4">
              {(['FLASHCARD', 'QUIZ'] as StudyMode[]).map((m) => (
                <button
                  key={m}
                  onClick={() => setMode(m)}
                  className={`py-3 rounded-2xl font-bold transition-all border-2 ${
                    settings.mode === m 
                      ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg' 
                      : 'bg-white border-slate-200 text-slate-600'
                  }`}
                >
                  {m}
                </button>
              ))}
            </div>
          </section>

          <section>
            <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-4">Included Features</h3>
            <div className="grid grid-cols-2 gap-3">
              {Object.values(IPAFeature).map((feature) => {
                const isActive = settings.activeFeatures.includes(feature);
                return (
                  <button
                    key={feature}
                    onClick={() => toggleFeature(feature)}
                    className={`flex items-center justify-between p-3 rounded-2xl border-2 transition-all ${
                      isActive ? 'bg-indigo-50 border-indigo-200 text-indigo-700' : 'bg-white border-slate-100 text-slate-400'
                    }`}
                  >
                    <span className="font-bold text-sm">{feature}</span>
                    {isActive && <Check className="w-4 h-4" />}
                  </button>
                );
              })}
            </div>
          </section>

          {settings.mode === 'QUIZ' && (
            <section className="animate-in fade-in slide-in-from-top-4 duration-300">
              <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-4 flex items-center gap-2">
                <EyeOff className="w-4 h-4" /> Feature to Hide
              </h3>
              <div className="grid grid-cols-2 gap-3">
                {settings.activeFeatures.map((feature) => (
                  <button
                    key={feature}
                    onClick={() => selectMasked(feature)}
                    className={`p-3 rounded-2xl border-2 font-bold text-sm transition-all ${
                      settings.maskedFeature === feature 
                        ? 'bg-red-50 border-red-200 text-red-700' 
                        : 'bg-white border-slate-100 text-slate-400'
                    }`}
                  >
                    {feature}
                  </button>
                ))}
              </div>
            </section>
          )}

          <button 
            onClick={onClose}
            className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black text-lg hover:bg-slate-800 transition-all shadow-xl shadow-slate-200"
          >
            START STUDYING
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { IPAFeature, IPACardData, AppSettings, CardState } from './types';
import { ipaDataset } from './data/ipaData';
import { Flashcard } from './components/Flashcard';
import { FoldedCard } from './components/FoldedCard';
import { SettingsOverlay } from './components/SettingsOverlay';
import { Settings, Layers, Microscope, Music, MoveHorizontal } from 'lucide-react';
import { synthesizeIPAWord } from './services/geminiService';

const App: React.FC = () => {
  const [settings, setSettings] = useState<AppSettings>({
    activeFeatures: [IPAFeature.SYMBOL, IPAFeature.LABEL],
    mode: 'FLASHCARD',
    maskedFeature: IPAFeature.LABEL
  });

  const [cardState, setCardState] = useState<CardState>({
    currentIndex: 0,
    isFlipped: false,
    currentSide: 0,
    userInput: '',
    feedback: 'none'
  });

  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [activeTab, setActiveTab] = useState<'study' | 'lab'>('study');
  const [labInput, setLabInput] = useState('');

  const touchStart = useRef<number | null>(null);
  const touchEnd = useRef<number | null>(null);

  const minSwipeDistance = 50;

  const currentCard = ipaDataset[cardState.currentIndex];

  const handleNext = useCallback(() => {
    setCardState(prev => ({
      ...prev,
      currentIndex: (prev.currentIndex + 1) % ipaDataset.length,
      isFlipped: false,
      userInput: '',
      feedback: 'none'
    }));
  }, []);

  const handlePrev = useCallback(() => {
    setCardState(prev => ({
      ...prev,
      currentIndex: (prev.currentIndex - 1 + ipaDataset.length) % ipaDataset.length,
      isFlipped: false,
      userInput: '',
      feedback: 'none'
    }));
  }, []);

  const onTouchStart = (e: React.TouchEvent) => {
    touchEnd.current = null;
    touchStart.current = e.targetTouches[0].clientX;
  };

  const onTouchMove = (e: React.TouchEvent) => {
    touchEnd.current = e.targetTouches[0].clientX;
  };

  const onTouchEnd = () => {
    if (!touchStart.current || !touchEnd.current) return;
    const distance = touchStart.current - touchEnd.current;
    const isLeftSwipe = distance > minSwipeDistance;
    const isRightSwipe = distance < -minSwipeDistance;
    if (isLeftSwipe) handleNext();
    if (isRightSwipe) handlePrev();
  };

  const handleFlip = () => {
    if (settings.activeFeatures.length === 2) {
      setCardState(prev => ({ ...prev, isFlipped: !prev.isFlipped }));
    }
  };

  const handleQuizSubmit = (input: string) => {
    const targetFeature = settings.maskedFeature || settings.activeFeatures[1];
    let isCorrect = false;

    const sanitizedInput = input.toLowerCase().trim();
    if (targetFeature === IPAFeature.SYMBOL) isCorrect = sanitizedInput === currentCard.symbol.toLowerCase();
    if (targetFeature === IPAFeature.LABEL) isCorrect = currentCard.label.toLowerCase().includes(sanitizedInput);
    if (targetFeature === IPAFeature.WORDS) isCorrect = currentCard.words.some(w => w.toLowerCase() === sanitizedInput);
    if (targetFeature === IPAFeature.SOUND) isCorrect = sanitizedInput === currentCard.symbol.toLowerCase();

    setCardState(prev => ({
      ...prev,
      feedback: isCorrect ? 'correct' : 'incorrect',
      isFlipped: true
    }));
  };

  const handleSynthesize = async () => {
    if (!labInput.trim()) return;
    await synthesizeIPAWord(labInput);
  };

  return (
    <div className="min-h-screen flex flex-col items-center justify-between pb-24 pt-8 px-4 max-w-md mx-auto relative select-none">

      <header className="w-full flex justify-between items-center mb-4">
        <div className="flex items-center gap-2">
          <div className="bg-indigo-600 p-2 rounded-xl text-white shadow-lg shadow-indigo-100">
            <Layers className="w-5 h-5" />
          </div>
          <h1 className="text-xl font-black text-slate-800 tracking-tight">IPA MASTER</h1>
        </div>
        <button 
          onClick={() => setIsSettingsOpen(true)}
