interface FlashcardProps {
  data: IPACardData;
  promptFeature: IPAFeature;
  maskedFeature: IPAFeature;
  isFlipped: boolean;
  onFlip: () => void;
  isQuiz: boolean;
  userInput: string;
  setUserInput: (val: string) => void;
  feedback: 'none' | 'correct' | 'incorrect';
  onSubmit: (val: string) => void;
  onMarkStatus?: (status: LearningStatus) => void;
}

const FeatureContent: React.FC<{ feature: IPAFeature; data: IPACardData }> = ({ feature, data }) => {
  switch (feature) {
    case IPAFeature.SYMBOL:
      return <div className="ipa-font text-8xl font-bold text-indigo-900">{data.symbol}</div>;
    case IPAFeature.LABEL:
      return <div className="text-2xl font-semibold text-slate-700 text-center px-4 leading-snug">{data.label}</div>;
    case IPAFeature.WORDS:
      return (
        <div className="flex flex-col items-center gap-2">
          <span className="text-sm uppercase tracking-widest text-slate-400 mb-2 font-bold">Examples</span>
          {data.words.map((w, i) => (
            <span key={i} className="text-xl font-medium text-slate-700">{w}</span>
          ))}
        </div>
      );
    case IPAFeature.SOUND:
      return (
        <button 
          onClick={(e) => { e.stopPropagation(); playIPASound(data.symbol); }}
          className="p-8 bg-indigo-50 rounded-full hover:bg-indigo-100 transition-colors group"
        >
          <Volume2 className="w-16 h-16 text-indigo-600 group-hover:scale-110 transition-transform" />
        </button>
      );
    default:
      return null;
  }
};

export const Flashcard: React.FC<FlashcardProps> = ({ 
  data, promptFeature, maskedFeature, isFlipped, onFlip, isQuiz, userInput, setUserInput, feedback, onSubmit, onMarkStatus 
}) => {
  const handleQuizSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSubmit(userInput);
  };

  return (
    <div className="w-full max-w-sm h-[420px] perspective-1000 cursor-pointer" onClick={onFlip}>
      <div className={`relative w-full h-full transition-transform duration-700 preserve-3d ${isFlipped ? 'rotate-y-180' : ''}`}>

        {/* Front */}
        <div className="absolute inset-0 bg-white rounded-3xl shadow-xl flex flex-col items-center justify-center border-2 border-slate-100 backface-hidden">
