          <div className="absolute bottom-4 right-6 text-slate-300 text-[10px] font-black uppercase tracking-widest">{promptFeature}</div>
        </div>

        {/* Back */}
        <div className="absolute inset-0 bg-white rounded-3xl shadow-xl flex flex-col items-center justify-center border-2 border-slate-100 backface-hidden rotate-y-180">
          {isQuiz && !isFlipped ? (
            <div className="p-6 w-full flex flex-col items-center gap-4" onClick={(e) => e.stopPropagation()}>
              <h3 className="text-sm font-bold text-slate-400 uppercase tracking-widest">Identify {maskedFeature.toLowerCase()}</h3>
              <form onSubmit={handleQuizSubmit} className="w-full">
                <input
                  autoFocus
                  type="text"
                  value={userInput}
                  onChange={(e) => setUserInput(e.target.value)}
                  className="w-full px-4 py-3 rounded-xl border-2 border-slate-200 focus:border-indigo-500 outline-none text-center text-xl font-bold"
                  placeholder="???"
                />
                <button 
                  type="submit"
                  className="w-full mt-4 bg-indigo-600 text-white py-3 rounded-xl font-bold hover:bg-indigo-700 transition-colors shadow-lg"
                >
                  CHECK
                </button>
              </form>
            </div>
          ) : (
            <div className="flex flex-col items-center gap-6">
              {feedback === 'correct' && <div className="text-green-500 flex items-center gap-2 font-bold animate-bounce"><CheckCircle className="w-6 h-6" /> CORRECT</div>}
              {feedback === 'incorrect' && <div className="text-red-500 flex items-center gap-2 font-bold"><XCircle className="w-6 h-6" /> INCORRECT</div>}

              <FeatureContent feature={maskedFeature} data={data} />

              {/* Learning Status Buttons - Only in Flashcard mode or after flipped */}
              {onMarkStatus && isFlipped && (
                <div className="flex gap-4 mt-4" onClick={(e) => e.stopPropagation()}>
                  <button 
                    onClick={() => onMarkStatus(LearningStatus.NO)}
                    className="p-3 bg-red-50 text-red-500 rounded-2xl hover:bg-red-100 transition-colors flex flex-col items-center gap-1"
                  >
                    <X className="w-6 h-6" />
                    <span className="text-[10px] font-bold">NO</span>
                  </button>
                  <button 
                    onClick={() => onMarkStatus(LearningStatus.MAYBE)}
                    className="p-3 bg-orange-50 text-orange-500 rounded-2xl hover:bg-orange-100 transition-colors flex flex-col items-center gap-1"
                  >
                    <HelpCircle className="w-6 h-6" />
                    <span className="text-[10px] font-bold">MAYBE</span>
                  </button>
                  <button 
                    onClick={() => onMarkStatus(LearningStatus.REMEMBERED)}
                    className="p-3 bg-green-50 text-green-500 rounded-2xl hover:bg-green-100 transition-colors flex flex-col items-center gap-1"
                  >
                    <Check className="w-6 h-6" />
                    <span className="text-[10px] font-bold">YES</span>
                  </button>
                </div>
              )}
            </div>
          )}
          <div className="absolute bottom-4 right-6 text-slate-300 text-[10px] font-black uppercase tracking-widest">{maskedFeature}</div>
        </div>

      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { IPAFeature, IPACardData, LearningStatus } from '../types';
import { Volume2, ChevronRight, ChevronLeft, CheckCircle, XCircle, Check, X, HelpCircle } from 'lucide-react';
import { playIPASound } from '../services/geminiService';

interface FoldedCardProps {
  data: IPACardData;
  promptFeature: IPAFeature;
  maskedFeature: IPAFeature;
  features: IPAFeature[];
  isQuiz?: boolean;
  userInput: string;
  setUserInput: (val: string) => void;
  feedback: 'none' | 'correct' | 'incorrect';
  onSubmit: (val: string) => void;
  onMarkStatus?: (status: LearningStatus) => void;
}

const FeatureIcon: React.FC<{ feature: IPAFeature }> = ({ feature }) => {
  switch (feature) {
    case IPAFeature.SYMBOL: return <span className="text-lg font-bold">Ω</span>;
    case IPAFeature.LABEL: return <span className="text-lg font-bold">abc</span>;
    case IPAFeature.WORDS: return <span className="text-lg font-bold">""</span>;
    case IPAFeature.SOUND: return <Volume2 className="w-5 h-5" />;
    default: return null;
  }
};

const FeatureDisplay: React.FC<{ feature: IPAFeature; data: IPACardData }> = ({ feature, data }) => {
  switch (feature) {
    case IPAFeature.SYMBOL:
      return <div className="ipa-font text-7xl font-bold text-indigo-900">{data.symbol}</div>;
    case IPAFeature.LABEL:
      return <div className="text-xl font-semibold text-slate-700 text-center px-4 leading-relaxed">{data.label}</div>;
    case IPAFeature.WORDS:
      return (
        <div className="flex flex-wrap justify-center gap-3">
          {data.words.map((w, i) => (
            <span key={i} className="px-4 py-2 bg-slate-100 rounded-full text-slate-700 font-medium">{w}</span>
          ))}
        </div>
      );
    case IPAFeature.SOUND:
      return (
        <button 
          onClick={() => playIPASound(data.symbol)}
          className="p-6 bg-indigo-600 rounded-full text-white shadow-lg hover:bg-indigo-700 transition-all active:scale-95"
        >
          <Volume2 className="w-10 h-10" />
        </button>
      );
    default: return null;
  }
};

export const FoldedCard: React.FC<FoldedCardProps> = ({ 
  data, promptFeature, maskedFeature, features, isQuiz, userInput, setUserInput, feedback, onSubmit, onMarkStatus 
}) => {
  const [activeSurface, setActiveSurface] = useState(0);

  // Set initial surface to promptFeature
  useEffect(() => {
    const promptIdx = features.indexOf(promptFeature);
    if (promptIdx !== -1) setActiveSurface(promptIdx);
  }, [promptFeature, features]);

  const nextSurface = () => setActiveSurface((s) => (s + 1) % features.length);
  const prevSurface = () => setActiveSurface((s) => (s - 1 + features.length) % features.length);

  const isCurrentSurfaceMasked = isQuiz && features[activeSurface] === maskedFeature && feedback === 'none';

  const handleQuizSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSubmit(userInput);
  };

  return (
    <div className="w-full max-w-sm h-[420px] relative flex flex-col items-center justify-center bg-white rounded-3xl shadow-2xl border border-slate-100 overflow-hidden">
      <div className="absolute top-0 right-0 w-16 h-16 bg-slate-100 -rotate-45 translate-x-8 -translate-y-8 shadow-inner"></div>

      <div className="absolute top-6 left-1/2 -translate-x-1/2 flex gap-2">
        {features.map((_, i) => (
          <div 
            key={i} 
            className={`h-2 rounded-full transition-all duration-300 ${i === activeSurface ? 'w-8 bg-indigo-50' : 'w-2 bg-slate-200'}`}
          />
        ))}
      </div>

      <div className="flex flex-col items-center justify-center p-8 text-center w-full" key={activeSurface}>
        <div className="text-xs font-bold text-slate-300 uppercase tracking-widest mb-6 flex items-center gap-2">
          <FeatureIcon feature={features[activeSurface]} />
          {features[activeSurface]}
        </div>

        {isCurrentSurfaceMasked ? (
          <div className="w-full max-w-[240px]">
            <form onSubmit={handleQuizSubmit} className="flex flex-col gap-4">
               <input
                autoFocus
                type="text"
                value={userInput}
                onChange={(e) => setUserInput(e.target.value)}
                className="w-full px-4 py-3 rounded-xl border-2 border-slate-200 focus:border-indigo-500 outline-none text-center text-xl font-bold"
                placeholder="Identify..."
              />
              <button 
                type="submit"
                className="bg-indigo-600 text-white py-3 rounded-xl font-bold hover:bg-indigo-700 transition-colors shadow-lg"
              >
                CHECK
              </button>
            </form>
          </div>
        ) : (
          <div className="animate-in fade-in zoom-in duration-300 flex flex-col items-center">
            {isQuiz && features[activeSurface] === maskedFeature && (
              <div className="mb-4 flex justify-center">
                {feedback === 'correct' ? <CheckCircle className="text-green-500 w-8 h-8" /> : <XCircle className="text-red-500 w-8 h-8" />}
              </div>
            )}
            <FeatureDisplay feature={features[activeSurface]} data={data} />

            {onMarkStatus && (
              <div className="flex gap-4 mt-8">
                <button onClick={() => onMarkStatus(LearningStatus.NO)} className="p-2 bg-red-50 text-red-500 rounded-xl"><X className="w-5 h-5"/></button>
                <button onClick={() => onMarkStatus(LearningStatus.MAYBE)} className="p-2 bg-orange-50 text-orange-500 rounded-xl"><HelpCircle className="w-5 h-5"/></button>
                <button onClick={() => onMarkStatus(LearningStatus.REMEMBERED)} className="p-2 bg-green-50 text-green-500 rounded-xl"><Check className="w-5 h-5"/></button>
              </div>
            )}
          </div>
        )}
      </div>

      <button onClick={prevSurface} className="absolute left-2 top-1/2 -translate-y-1/2 p-2 text-slate-300 hover:text-indigo-600 transition-colors"><ChevronLeft className="w-8 h-8" /></button>
      <button onClick={nextSurface} className="absolute right-2 top-1/2 -translate-y-1/2 p-2 text-slate-300 hover:text-indigo-600 transition-colors"><ChevronRight className="w-8 h-8" /></button>

      <div className="absolute bottom-0 inset-x-0 h-12 flex">
        {features.map((feature, i) => (
          <button
            key={i}
            onClick={() => setActiveSurface(i)}
            className={`flex-1 flex items-center justify-center border-t transition-all ${
              i === activeSurface 
                ? 'bg-indigo-50 text-indigo-600 border-indigo-200 font-black text-xs' 
                : 'bg-slate-50 text-slate-400 border-slate-100 text-xs'
            }`}
          >
            <FeatureIcon feature={feature} />
          </button>
        ))}
      </div>
    </div>
  );
};

import React from 'react';
import { IPAFeature, AppSettings, StudyMode } from '../types';
import { X, Check, EyeOff, Eye, RotateCcw } from 'lucide-react';

interface SettingsOverlayProps {
  settings: AppSettings;
  onUpdate: (settings: AppSettings) => void;
  onClose: () => void;
  onReset: () => void;
}

export const SettingsOverlay: React.FC<SettingsOverlayProps> = ({ settings, onUpdate, onClose, onReset }) => {
  const toggleFeature = (feature: IPAFeature) => {
    let newFeatures = [...settings.activeFeatures];
    if (newFeatures.includes(feature)) {
      if (newFeatures.length > 2) {
        newFeatures = newFeatures.filter(f => f !== feature);
      }
    } else {
      newFeatures.push(feature);
    }

    onUpdate({ ...settings, activeFeatures: newFeatures });
  };

  const setMode = (mode: StudyMode) => {
    onUpdate({ ...settings, mode });
  };

  return (
    <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-50 flex items-end sm:items-center justify-center p-4">
      <div className="bg-white w-full max-w-md rounded-[2.5rem] p-8 shadow-2xl animate-in slide-in-from-bottom duration-300 max-h-[90vh] overflow-y-auto">
        <div className="flex justify-between items-center mb-8">
          <h2 className="text-2xl font-black text-slate-800 tracking-tight">STUDY SETUP</h2>
          <button onClick={onClose} className="p-2 bg-slate-100 rounded-full hover:bg-slate-200 transition-colors">
            <X className="w-6 h-6 text-slate-600" />
          </button>
        </div>

        <div className="space-y-8">
          <section>
            <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-4">Study Mode</h3>
            <div className="grid grid-cols-2 gap-4">
              {(['FLASHCARD', 'QUIZ'] as StudyMode[]).map((m) => (
                <button
                  key={m}
                  onClick={() => setMode(m)}
                  className={`py-3 rounded-2xl font-bold transition-all border-2 ${
                    settings.mode === m 
                      ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg' 
                      : 'bg-white border-slate-200 text-slate-600'
                  }`}
                >
                  {m}
                </button>
              ))}
            </div>
          </section>

          <section>
            <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-4">Features in Card</h3>
            <div className="grid grid-cols-2 gap-3">
              {Object.values(IPAFeature).map((feature) => {
                const isActive = settings.activeFeatures.includes(feature);
                return (
                  <button
                    key={feature}
                    onClick={() => toggleFeature(feature)}
                    className={`flex items-center justify-between p-3 rounded-2xl border-2 transition-all ${
                      isActive ? 'bg-indigo-50 border-indigo-200 text-indigo-700' : 'bg-white border-slate-100 text-slate-400'
                    }`}
                  >
                    <span className="font-bold text-sm">{feature}</span>
                    {isActive && <Check className="w-4 h-4" />}
                  </button>
                );
              })}
            </div>
          </section>

          <div className="grid grid-cols-2 gap-6">
            <section>
              <h3 className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-3 flex items-center gap-2">
                <Eye className="w-3 h-3" /> Prompt
              </h3>
              <div className="flex flex-col gap-2">
                {settings.activeFeatures.map((f) => (
                  <button
                    key={f}
                    onClick={() => onUpdate({ ...settings, promptFeature: f })}
                    className={`p-2 rounded-xl border-2 text-xs font-bold transition-all ${
                      settings.promptFeature === f ? 'bg-indigo-50 border-indigo-200 text-indigo-700' : 'bg-white border-slate-100 text-slate-400'
                    }`}
                  >
                    {f}
                  </button>
                ))}
              </div>
            </section>

            <section>
              <h3 className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-3 flex items-center gap-2">
                <EyeOff className="w-3 h-3" /> Answer
              </h3>
              <div className="flex flex-col gap-2">
                {settings.activeFeatures.map((f) => (
                  <button
                    key={f}
                    onClick={() => onUpdate({ ...settings, maskedFeature: f })}
                    className={`p-2 rounded-xl border-2 text-xs font-bold transition-all ${
                      settings.maskedFeature === f ? 'bg-indigo-50 border-indigo-200 text-indigo-700' : 'bg-white border-slate-100 text-slate-400'
                    }`}
                  >
                    {f}
                  </button>
                ))}
              </div>
            </section>
          </div>

          <div className="pt-4 border-t border-slate-100 flex flex-col gap-4">
            <button 
              onClick={onReset}
              className="w-full py-4 border-2 border-slate-100 text-slate-500 rounded-2xl font-black text-sm flex items-center justify-center gap-2 hover:bg-slate-50"
            >
              <RotateCcw className="w-4 h-4" /> RESET ALL PROGRESS
            </button>
            <button 
              onClick={onClose}
              className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black text-lg hover:bg-slate-800 transition-all shadow-xl shadow-slate-200"
            >
              START STUDYING
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

