import React, { useState, useEffect, useCallback, useRef } from 'react';
import { IPAFeature, IPACardData, AppSettings, CardState, LearningStatus } from './types';
import { ipaDataset } from './data/ipaData';
import { Flashcard } from './components/Flashcard';
import { FoldedCard } from './components/FoldedCard';
import { SettingsOverlay } from './components/SettingsOverlay';
import { Settings, Layers, Microscope, Music, MoveHorizontal, RotateCcw, ChevronLeft, ChevronRight } from 'lucide-react';
import { playIPASound, playSynthesizedWord } from './services/audioService';

const App: React.FC = () => {
  const [settings, setSettings] = useState<AppSettings>({
    activeFeatures: [IPAFeature.SYMBOL, IPAFeature.LABEL],
    promptFeature: IPAFeature.SYMBOL,
    maskedFeature: IPAFeature.LABEL,
    mode: 'FLASHCARD'
  });

  const [learnedMap, setLearnedMap] = useState<Record<string, LearningStatus>>(() => {
    const saved = localStorage.getItem('learned_map');
    return saved ? JSON.parse(saved) : {};
  });

  const [studyQueue, setStudyQueue] = useState<string[]>([]);

  const [cardState, setCardState] = useState<CardState>({
    currentQueueIndex: 0,
    isFlipped: false,
    userInput: '',
    feedback: 'none'
  });

  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [activeTab, setActiveTab] = useState<'study' | 'lab'>('study');
  const [labInput, setLabInput] = useState('');

  const touchStart = useRef<number | null>(null);
  const touchEnd = useRef<number | null>(null);

  // Initialize queue
  useEffect(() => {
    const freshQueue = ipaDataset
      .filter(card => learnedMap[card.id] !== LearningStatus.REMEMBERED)
      .map(card => card.id);

    if (freshQueue.length > 0) {
      // Basic shuffle
      freshQueue.sort(() => Math.random() - 0.5);
      setStudyQueue(freshQueue);
    } else {
      setStudyQueue([]);
    }
    setCardState(prev => ({ ...prev, currentQueueIndex: 0, isFlipped: false, userInput: '', feedback: 'none' }));
  }, [learnedMap, settings.mode]);

  useEffect(() => {
    localStorage.setItem('learned_map', JSON.stringify(learnedMap));
  }, [learnedMap]);

  const handleNext = useCallback(() => {
    if (studyQueue.length === 0) return;
    setCardState(prev => ({
      ...prev,
      currentQueueIndex: (prev.currentQueueIndex + 1) % studyQueue.length,
      isFlipped: false,
      userInput: '',
      feedback: 'none'
    }));
  }, [studyQueue]);

  const handlePrev = useCallback(() => {
    if (studyQueue.length === 0) return;
    setCardState(prev => ({
      ...prev,
      currentQueueIndex: (prev.currentQueueIndex - 1 + studyQueue.length) % studyQueue.length,
      isFlipped: false,
      userInput: '',
      feedback: 'none'
    }));
  }, [studyQueue]);

  // Keyboard navigation
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.target instanceof HTMLInputElement) return;
      if (e.key === 'ArrowRight') handleNext();
      if (e.key === 'ArrowLeft') handlePrev();
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleNext, handlePrev]);

  const onTouchStart = (e: React.TouchEvent) => {
    touchEnd.current = null;
    touchStart.current = e.targetTouches[0].clientX;
  };

  const onTouchMove = (e: React.TouchEvent) => {
    touchEnd.current = e.targetTouches[0].clientX;
  };

  const onTouchEnd = () => {
    if (!touchStart.current || !touchEnd.current) return;
    const distance = touchStart.current - touchEnd.current;
    if (distance > 50) handleNext();
    if (distance < -50) handlePrev();
  };

  const currentCardId = studyQueue[cardState.currentQueueIndex];
  const currentCard = ipaDataset.find(c => c.id === currentCardId);

  const handleMarkStatus = (status: LearningStatus) => {
    if (!currentCard) return;
    if (status === LearningStatus.REMEMBERED) {
      setLearnedMap(prev => ({ ...prev, [currentCard.id]: LearningStatus.REMEMBERED }));
    } else {
      // Keep in queue, move to next
      handleNext();
    }
  };

  const handleQuizSubmit = (input: string) => {
    if (!currentCard) return;
    const targetFeature = settings.maskedFeature;
    let isCorrect = false;

    const sanitizedInput = input.toLowerCase().trim();
    if (targetFeature === IPAFeature.SYMBOL) isCorrect = sanitizedInput === currentCard.symbol.toLowerCase();
    else if (targetFeature === IPAFeature.LABEL) isCorrect = currentCard.label.toLowerCase().includes(sanitizedInput);
    else if (targetFeature === IPAFeature.WORDS) isCorrect = currentCard.words.some(w => w.toLowerCase() === sanitizedInput);
    else if (targetFeature === IPAFeature.SOUND) isCorrect = sanitizedInput === currentCard.symbol.toLowerCase();

    if (isCorrect) {
      setCardState(prev => ({ ...prev, feedback: 'correct', isFlipped: true }));
      // Automatically mark as remembered if correct in quiz to remove from this session's pool
      setTimeout(() => {
        setLearnedMap(prev => ({ ...prev, [currentCard.id]: LearningStatus.REMEMBERED }));
      }, 1000);
    } else {
      setCardState(prev => ({ ...prev, feedback: 'incorrect', isFlipped: true }));
      // Keep it repeated: push this ID back to the end of the queue
      setStudyQueue(prev => [...prev, currentCard.id]);
    }
  };

  const resetAll = () => {
    setLearnedMap({});
    localStorage.removeItem('learned_map');
    setIsSettingsOpen(false);
  };

  return (
    <div className="min-h-screen flex flex-col items-center justify-between pb-24 pt-8 px-4 max-w-md mx-auto relative select-none">

      <header className="w-full flex justify-between items-center mb-4">
        <div className="flex items-center gap-2">
          <div className="bg-indigo-600 p-2 rounded-xl text-white shadow-lg shadow-indigo-100">
            <Layers className="w-5 h-5" />
          </div>
          <h1 className="text-xl font-black text-slate-800 tracking-tight">IPA MASTER</h1>
        </div>
        <button 
          onClick={() => setIsSettingsOpen(true)}
          className="p-3 bg-white rounded-2xl shadow-sm border border-slate-100 text-slate-400 hover:text-indigo-600 transition-all hover:shadow-md"
        >
          <Settings className="w-6 h-6" />
        </button>
      </header>

      {activeTab === 'study' ? (
        <main className="w-full flex-grow flex flex-col items-center justify-center gap-6">
          {studyQueue.length > 0 && currentCard ? (
            <div className="w-full relative flex flex-col items-center gap-8">
              <div 
                className="w-full flex justify-center h-[420px] relative group"
                onTouchStart={onTouchStart}
                onTouchMove={onTouchMove}
                onTouchEnd={onTouchEnd}
              >
                {settings.activeFeatures.length === 2 ? (
                  <Flashcard 
                    data={currentCard}
                    promptFeature={settings.promptFeature}
                    maskedFeature={settings.maskedFeature}
                    isFlipped={cardState.isFlipped}
                    onFlip={() => setCardState(p => ({ ...p, isFlipped: !p.isFlipped }))}
                    isQuiz={settings.mode === 'QUIZ'}
                    userInput={cardState.userInput}
                    setUserInput={(v) => setCardState(p => ({ ...p, userInput: v }))}
                    feedback={cardState.feedback}
                    onSubmit={handleQuizSubmit}
                    onMarkStatus={settings.mode === 'FLASHCARD' ? handleMarkStatus : undefined}
                  />
                ) : (
                  <FoldedCard 
                    data={currentCard}
                    promptFeature={settings.promptFeature}
                    maskedFeature={settings.maskedFeature}
                    features={settings.activeFeatures}
                    isQuiz={settings.mode === 'QUIZ'}
                    userInput={cardState.userInput}
                    setUserInput={(v) => setCardState(p => ({ ...p, userInput: v }))}
                    feedback={cardState.feedback}
                    onSubmit={handleQuizSubmit}
                    onMarkStatus={settings.mode === 'FLASHCARD' ? handleMarkStatus : undefined}
                  />
                )}
              </div>

              {/* Navigation Arrows */}
              <div className="flex items-center justify-center gap-8 w-full mt-4">
                <button 
                  onClick={handlePrev}
                  className="p-4 bg-white rounded-full shadow-lg border border-slate-100 text-slate-400 hover:text-indigo-600 transition-all hover:scale-110 active:scale-95"
                  aria-label="Previous card"
                >
                  <ChevronLeft className="w-8 h-8" />
                </button>
                <div className="text-slate-400 font-black text-lg tracking-tighter bg-white px-6 py-2 rounded-full shadow-sm border border-slate-50 min-w-[100px] text-center">
                  {cardState.currentQueueIndex + 1} <span className="opacity-20 mx-1">/</span> {studyQueue.length}
                </div>
                <button 
                  onClick={handleNext}
                  className="p-4 bg-white rounded-full shadow-lg border border-slate-100 text-slate-400 hover:text-indigo-600 transition-all hover:scale-110 active:scale-95"
                  aria-label="Next card"
                >
                  <ChevronRight className="w-8 h-8" />
                </button>
              </div>

              <div className="text-[10px] font-black uppercase tracking-widest text-slate-300 flex items-center gap-2 opacity-50">
                <MoveHorizontal className="w-3 h-3" />
                Swipe or use arrows
              </div>
            </div>
          ) : (
            <div className="text-center p-12 bg-white rounded-[3rem] shadow-xl border border-slate-100 w-full animate-in fade-in zoom-in">
              <RotateCcw className="w-16 h-16 text-indigo-500 mx-auto mb-6" />
              <h2 className="text-2xl font-black text-slate-800 mb-2">Queue Clear!</h2>
              <p className="text-slate-400 text-sm mb-8 leading-relaxed">You've mastered all cards in this session. Great job!</p>
              <button 
                onClick={resetAll}
                className="w-full py-4 bg-indigo-600 text-white rounded-2xl font-black text-lg shadow-xl shadow-indigo-100 active:scale-95 transition-all"
              >
                RESET PROGRESS
              </button>
            </div>
          )}
        </main>
      ) : (
        <main className="w-full flex-grow flex flex-col items-center justify-start py-8 gap-8 animate-in fade-in duration-300">
          <div className="bg-white p-8 rounded-[2.5rem] w-full border border-slate-100 shadow-xl shadow-slate-100">
            <div className="flex items-center gap-3 mb-6">
              <Microscope className="w-6 h-6 text-indigo-600" />
              <h2 className="text-xl font-black text-slate-800">IPA LAB</h2>
            </div>
            <p className="text-slate-500 text-sm mb-6 leading-relaxed font-medium">
              Enter symbols to synthesize sound (Future Development). For now, it plays the standard character sound.
            </p>
            <div className="bg-slate-50 p-4 rounded-3xl shadow-inner border border-slate-200 mb-6">
              <input 
                type="text"
                value={labInput}
                onChange={(e) => setLabInput(e.target.value)}
                placeholder="Type symbols..."
                className="w-full bg-transparent text-3xl font-bold text-slate-900 outline-none ipa-font placeholder:text-slate-200 text-center"
              />
            </div>
            <button 
              onClick={() => playSynthesizedWord(labInput)}
              disabled={!labInput.trim()}
              className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black flex items-center justify-center gap-3 shadow-xl shadow-indigo-100 disabled:opacity-50 hover:bg-indigo-700 transition-all active:scale-95"
            >
              <Music className="w-5 h-5" />
              PLAY SYNTHESIS
            </button>
          </div>
        </main>
      )}

      <nav className="fixed bottom-8 left-1/2 -translate-x-1/2 bg-slate-900/95 backdrop-blur-xl rounded-[2.5rem] px-10 py-5 flex gap-10 items-center shadow-2xl z-40 border border-white/10">
        <button 
          onClick={() => setActiveTab('study')}
          className={`flex flex-col items-center gap-1.5 transition-all ${activeTab === 'study' ? 'text-indigo-400 scale-110' : 'text-slate-500 hover:text-slate-300'}`}
        >
          <Layers className="w-6 h-6" />
          <span className="text-[10px] font-black uppercase tracking-widest">Study</span>
        </button>
        <div className="w-px h-6 bg-slate-800"></div>
        <button 
          onClick={() => setActiveTab('lab')}
          className={`flex flex-col items-center gap-1.5 transition-all ${activeTab === 'lab' ? 'text-indigo-400 scale-110' : 'text-slate-500 hover:text-slate-300'}`}
        >
          <Microscope className="w-6 h-6" />
          <span className="text-[10px] font-black uppercase tracking-widest">Lab</span>
        </button>
      </nav>

      {isSettingsOpen && (
        <SettingsOverlay 
          settings={settings}
          onUpdate={setSettings}
          onClose={() => setIsSettingsOpen(false)}
          onReset={resetAll}
        />
      )}
    </div>
  );
};

