      );
    default: return null;
  }
};

export const FoldedCard: React.FC<FoldedCardProps> = ({ 
  data, promptFeature, maskedFeature, features, isQuiz, userInput, setUserInput, feedback, onSubmit, onMarkStatus 
}) => {
  const [activeSurface, setActiveSurface] = useState(0);

  useEffect(() => {
    const promptIdx = features.indexOf(promptFeature);
    if (promptIdx !== -1) setActiveSurface(promptIdx);
  }, [promptFeature, features]);

  const nextSurface = () => setActiveSurface((s) => (s + 1) % features.length);
  const prevSurface = () => setActiveSurface((s) => (s - 1 + features.length) % features.length);

  const isCurrentSurfaceMasked = isQuiz && features[activeSurface] === maskedFeature && feedback === 'none';

  const handleQuizSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSubmit(userInput);
  };

  return (
    <div 
      className="w-full max-w-sm h-[420px] relative flex flex-col items-center justify-center bg-white rounded-3xl shadow-2xl border border-slate-100 overflow-hidden cursor-pointer"
      onClick={nextSurface}
    >
      <div className="absolute top-0 right-0 w-16 h-16 bg-slate-100 -rotate-45 translate-x-8 -translate-y-8 shadow-inner"></div>

      <div className="absolute top-6 left-1/2 -translate-x-1/2 flex gap-2">
        {features.map((_, i) => (
          <div 
            key={i} 
            className={`h-2 rounded-full transition-all duration-300 ${i === activeSurface ? 'w-8 bg-indigo-200' : 'w-2 bg-slate-200'}`}
          />
        ))}
      </div>

      <div className="flex flex-col items-center justify-center p-8 text-center w-full" key={activeSurface}>
        <div className="text-xs font-bold text-slate-300 uppercase tracking-widest mb-6 flex items-center gap-2">
          <FeatureIcon feature={features[activeSurface]} />
          {features[activeSurface]}
        </div>

        {isCurrentSurfaceMasked ? (
          <div className="w-full max-w-[240px]" onClick={(e) => e.stopPropagation()}>
            <form onSubmit={handleQuizSubmit} className="flex flex-col gap-4">
               <input
                autoFocus
                type="text"
                value={userInput}
                onChange={(e) => setUserInput(e.target.value)}
                className="w-full px-4 py-3 rounded-xl border-2 border-slate-200 focus:border-indigo-500 outline-none text-center text-xl font-bold"
                placeholder="Identify..."
              />
              <button 
                type="submit"
                className="bg-indigo-600 text-white py-3 rounded-xl font-bold hover:bg-indigo-700 transition-colors shadow-lg"
              >
                CHECK
              </button>
            </form>
          </div>
        ) : (
          <div className="animate-in fade-in zoom-in duration-300 flex flex-col items-center">
            {isQuiz && features[activeSurface] === maskedFeature && (
              <div className="mb-4 flex justify-center">
                {feedback === 'correct' ? <CheckCircle className="text-green-500 w-8 h-8" /> : <XCircle className="text-red-500 w-8 h-8" />}
              </div>
            )}
            <FeatureDisplay feature={features[activeSurface]} data={data} />

            {onMarkStatus && (
              <div className="flex gap-4 mt-8" onClick={(e) => e.stopPropagation()}>
                <button 
                  onClick={() => onMarkStatus(LearningStatus.NO)} 
                  className="p-3 bg-red-50 text-red-500 rounded-xl hover:bg-red-100 transition-all"
                  aria-label="No"
                >
                  <X className="w-6 h-6"/>
                </button>
                <button 
                  onClick={() => onMarkStatus(LearningStatus.MAYBE)} 
                  className="p-3 bg-orange-50 text-orange-500 rounded-xl hover:bg-orange-100 transition-all"
                  aria-label="Maybe"
                >
                  <HelpCircle className="w-6 h-6"/>
                </button>
                <button 
                  onClick={() => onMarkStatus(LearningStatus.REMEMBERED)} 
                  className="p-3 bg-green-50 text-green-500 rounded-xl hover:bg-green-100 transition-all"
                  aria-label="Remembered"
                >
                  <Check className="w-6 h-6"/>
                </button>
              </div>
            )}
          </div>
        )}
      </div>

      <button 
        onClick={(e) => { e.stopPropagation(); prevSurface(); }} 
        className="absolute left-2 top-1/2 -translate-y-1/2 p-2 text-slate-300 hover:text-indigo-600 transition-colors"
      >
        <ChevronLeft className="w-8 h-8" />
      </button>
      <button 
        onClick={(e) => { e.stopPropagation(); nextSurface(); }} 
        className="absolute right-2 top-1/2 -translate-y-1/2 p-2 text-slate-300 hover:text-indigo-600 transition-colors"
      >
        <ChevronRight className="w-8 h-8" />
      </button>

      <div className="absolute bottom-0 inset-x-0 h-12 flex">
        {features.map((feature, i) => (
          <button
            key={i}
            onClick={(e) => { e.stopPropagation(); setActiveSurface(i); }}
            className={`flex-1 flex items-center justify-center border-t transition-all ${
              i === activeSurface 
                ? 'bg-indigo-50 text-indigo-600 border-indigo-200 font-black text-xs' 
                : 'bg-slate-50 text-slate-400 border-slate-100 text-[10px]'
            }`}
          >
            <FeatureIcon feature={feature} />
          </button>
        ))}
      </div>
    </div>
  );
};

import React from 'react';
import { IPAFeature, AppSettings, StudyMode } from '../types';
import { X, Check, EyeOff, Eye, RotateCcw } from 'lucide-react';

interface SettingsOverlayProps {
  settings: AppSettings;
  onUpdate: (settings: AppSettings) => void;
  onClose: () => void;
  onReset: () => void;
}

export const SettingsOverlay: React.FC<SettingsOverlayProps> = ({ settings, onUpdate, onClose, onReset }) => {
  const toggleFeature = (feature: IPAFeature) => {
    let newFeatures = [...settings.activeFeatures];
    if (newFeatures.includes(feature)) {
      if (newFeatures.length > 2) {
        newFeatures = newFeatures.filter(f => f !== feature);
      }
    } else {
      newFeatures.push(feature);
    }

    // Ensure prompt/masked are valid based on new features
    let nextPrompt = settings.promptFeature;
    let nextMasked = settings.maskedFeature;

    if (!newFeatures.includes(nextPrompt)) {
      nextPrompt = newFeatures[0];
    }

    if (!newFeatures.includes(nextMasked) || nextMasked === IPAFeature.SOUND) {
      // Find the first non-sound feature to be the default masked feature
      nextMasked = newFeatures.find(f => f !== IPAFeature.SOUND && f !== nextPrompt) || newFeatures.find(f => f !== IPAFeature.SOUND) || newFeatures[0];
    }

    onUpdate({ ...settings, activeFeatures: newFeatures, promptFeature: nextPrompt, maskedFeature: nextMasked });
  };

  const setMode = (mode: StudyMode) => {
    onUpdate({ ...settings, mode });
  };

  const setPrompt = (f: IPAFeature) => {
    // If we select a prompt that is currently the answer, we might need to swap them or pick a new answer
    let nextMasked = settings.maskedFeature;
    if (f === nextMasked) {
      // Find another valid answer
      nextMasked = settings.activeFeatures.find(feat => feat !== f && feat !== IPAFeature.SOUND) || settings.activeFeatures[0];
    }
    onUpdate({ ...settings, promptFeature: f, maskedFeature: nextMasked });
  };

  const setMasked = (f: IPAFeature) => {
    if (f === IPAFeature.SOUND) return; // Prevent sound as answer
    let nextPrompt = settings.promptFeature;
    if (f === nextPrompt) {
      nextPrompt = settings.activeFeatures.find(feat => feat !== f) || settings.activeFeatures[0];
    }
    onUpdate({ ...settings, maskedFeature: f, promptFeature: nextPrompt });
  };

  return (
    <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-50 flex items-end sm:items-center justify-center p-4">
      <div className="bg-white w-full max-w-md rounded-[2.5rem] p-8 shadow-2xl animate-in slide-in-from-bottom duration-300 max-h-[90vh] overflow-y-auto">
        <div className="flex justify-between items-center mb-8">
          <h2 className="text-2xl font-black text-slate-800 tracking-tight">STUDY SETUP</h2>
          <button onClick={onClose} className="p-2 bg-slate-100 rounded-full hover:bg-slate-200 transition-colors">
            <X className="w-6 h-6 text-slate-600" />
          </button>
        </div>

        <div className="space-y-8">
          <section>
            <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-4">Study Mode</h3>
            <div className="grid grid-cols-2 gap-4">
              {(['FLASHCARD', 'QUIZ'] as StudyMode[]).map((m) => (
                <button
                  key={m}
                  onClick={() => setMode(m)}
                  className={`py-3 rounded-2xl font-bold transition-all border-2 ${
                    settings.mode === m 
                      ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg' 
                      : 'bg-white border-slate-200 text-slate-600'
                  }`}
                >
                  {m}
                </button>
              ))}
            </div>
          </section>

          <section>
            <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-4">Features in Card</h3>
            <div className="grid grid-cols-2 gap-3">
              {Object.values(IPAFeature).map((feature) => {
                const isActive = settings.activeFeatures.includes(feature);
                return (
                  <button
                    key={feature}
                    onClick={() => toggleFeature(feature)}
                    className={`flex items-center justify-between p-3 rounded-2xl border-2 transition-all ${
                      isActive ? 'bg-indigo-50 border-indigo-200 text-indigo-700' : 'bg-white border-slate-100 text-slate-400'
                    }`}
                  >
                    <span className="font-bold text-sm">{feature}</span>
                    {isActive && <Check className="w-4 h-4" />}
                  </button>
                );
              })}
            </div>
          </section>

          <div className="grid grid-cols-2 gap-6">
            <section>
              <h3 className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-3 flex items-center gap-2">
                <Eye className="w-3 h-3" /> Prompt
              </h3>
              <div className="flex flex-col gap-2">
                {settings.activeFeatures.map((f) => (
                  <button
                    key={f}
                    onClick={() => setPrompt(f)}
                    className={`p-2 rounded-xl border-2 text-xs font-bold transition-all ${
                      settings.promptFeature === f ? 'bg-indigo-50 border-indigo-200 text-indigo-700' : 'bg-white border-slate-100 text-slate-400'
                    }`}
                  >
                    {f}
                  </button>
                ))}
              </div>
            </section>

            <section>
              <h3 className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-3 flex items-center gap-2">
                <EyeOff className="w-3 h-3" /> Answer
              </h3>
              <div className="flex flex-col gap-2">
                {settings.activeFeatures
                  .filter(f => f !== IPAFeature.SOUND)
                  .map((f) => (
                  <button
                    key={f}
                    onClick={() => setMasked(f)}
                    className={`p-2 rounded-xl border-2 text-xs font-bold transition-all ${
                      settings.maskedFeature === f ? 'bg-indigo-50 border-indigo-200 text-indigo-700' : 'bg-white border-slate-100 text-slate-400'
                    }`}
                  >
                    {f}
                  </button>
                ))}
                {settings.activeFeatures.filter(f => f !== IPAFeature.SOUND).length === 0 && (
                  <div className="text-[10px] text-slate-400 italic">Select more features</div>
                )}
              </div>
            </section>
          </div>

          <div className="pt-4 border-t border-slate-100 flex flex-col gap-4">
            <button 
              onClick={onReset}
              className="w-full py-4 border-2 border-slate-100 text-slate-500 rounded-2xl font-black text-sm flex items-center justify-center gap-2 hover:bg-slate-50"
            >
              <RotateCcw className="w-4 h-4" /> RESET ALL PROGRESS
            </button>
            <button 
              onClick={onClose}
              className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black text-lg hover:bg-slate-800 transition-all shadow-xl shadow-slate-200"
            >
              START STUDYING
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { IPAFeature, IPACardData, AppSettings, CardState, LearningStatus } from './types';
import { ipaDataset } from './data/ipaData';
import { Flashcard } from './components/Flashcard';
import { FoldedCard } from './components/FoldedCard';
import { SettingsOverlay } from './components/SettingsOverlay';
import { Settings, Layers, Microscope, Music, MoveHorizontal, RotateCcw, ChevronLeft, ChevronRight } from 'lucide-react';
import { playIPASound, playSynthesizedWord } from './services/audioService';

const App: React.FC = () => {
  const [settings, setSettings] = useState<AppSettings>({
    activeFeatures: [IPAFeature.SYMBOL, IPAFeature.LABEL],
    promptFeature: IPAFeature.SYMBOL,
    maskedFeature: IPAFeature.LABEL,
    mode: 'FLASHCARD'
  });

  const [learnedMap, setLearnedMap] = useState<Record<string, LearningStatus>>(() => {
    const saved = localStorage.getItem('learned_map');
    return saved ? JSON.parse(saved) : {};
  });

  const [studyQueue, setStudyQueue] = useState<string[]>([]);

  const [cardState, setCardState] = useState<CardState>({
    currentQueueIndex: 0,
    isFlipped: false,
    userInput: '',
    feedback: 'none'
  });

  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [activeTab, setActiveTab] = useState<'study' | 'lab'>('study');
  const [labInput, setLabInput] = useState('');

  const touchStart = useRef<number | null>(null);
  const touchEnd = useRef<number | null>(null);

  // Initialize queue
  useEffect(() => {
    const freshQueue = ipaDataset
      .filter(card => learnedMap[card.id] !== LearningStatus.REMEMBERED)
      .map(card => card.id);

    if (freshQueue.length > 0) {
      // Basic shuffle
      freshQueue.sort(() => Math.random() - 0.5);
      setStudyQueue(freshQueue);
    } else {
      setStudyQueue([]);
    }
    setCardState(prev => ({ ...prev, currentQueueIndex: 0, isFlipped: false, userInput: '', feedback: 'none' }));
  }, [learnedMap, settings.mode]);

  useEffect(() => {
    localStorage.setItem('learned_map', JSON.stringify(learnedMap));
  }, [learnedMap]);

  const handleNext = useCallback(() => {
    if (studyQueue.length === 0) return;
    setCardState(prev => ({
      ...prev,
      currentQueueIndex: (prev.currentQueueIndex + 1) % studyQueue.length,
      isFlipped: false,
      userInput: '',
      feedback: 'none'
    }));
  }, [studyQueue]);

  const handlePrev = useCallback(() => {
    if (studyQueue.length === 0) return;
    setCardState(prev => ({
      ...prev,
      currentQueueIndex: (prev.currentQueueIndex - 1 + studyQueue.length) % studyQueue.length,
      isFlipped: false,
      userInput: '',
      feedback: 'none'
    }));
  }, [studyQueue]);

  // Keyboard navigation
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.target instanceof HTMLInputElement) return;
      if (e.key === 'ArrowRight') handleNext();
      if (e.key === 'ArrowLeft') handlePrev();
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleNext, handlePrev]);

  const onTouchStart = (e: React.TouchEvent) => {
    touchEnd.current = null;
    touchStart.current = e.targetTouches[0].clientX;
  };

  const onTouchMove = (e: React.TouchEvent) => {
    touchEnd.current = e.targetTouches[0].clientX;
  };

  const onTouchEnd = () => {
    if (!touchStart.current || !touchEnd.current) return;
    const distance = touchStart.current - touchEnd.current;
    if (distance > 50) handleNext();
    if (distance < -50) handlePrev();
  };

  const currentCardId = studyQueue[cardState.currentQueueIndex];
  const currentCard = ipaDataset.find(c => c.id === currentCardId);

  const handleMarkStatus = (status: LearningStatus) => {
    if (!currentCard) return;
    if (status === LearningStatus.REMEMBERED) {
      setLearnedMap(prev => ({ ...prev, [currentCard.id]: LearningStatus.REMEMBERED }));
    } else {
      // Keep in queue, move to next
      handleNext();
    }
  };

  const handleQuizSubmit = (input: string) => {
    if (!currentCard) return;
    const targetFeature = settings.maskedFeature;
    let isCorrect = false;

    const sanitizedInput = input.toLowerCase().trim();
    if (targetFeature === IPAFeature.SYMBOL) isCorrect = sanitizedInput === currentCard.symbol.toLowerCase();
    else if (targetFeature === IPAFeature.LABEL) isCorrect = currentCard.label.toLowerCase().includes(sanitizedInput);
    else if (targetFeature === IPAFeature.WORDS) isCorrect = currentCard.words.some(w => w.toLowerCase() === sanitizedInput);
    // Sound is no longer an answer, so no check needed here.

    if (isCorrect) {
      setCardState(prev => ({ ...prev, feedback: 'correct', isFlipped: true }));
      // Automatically mark as remembered if correct in quiz to remove from this session's pool
      setTimeout(() => {
        setLearnedMap(prev => ({ ...prev, [currentCard.id]: LearningStatus.REMEMBERED }));
      }, 1000);
    } else {
      setCardState(prev => ({ ...prev, feedback: 'incorrect', isFlipped: true }));
      // Keep it repeated: push this ID back to the end of the queue
      setStudyQueue(prev => [...prev, currentCard.id]);
    }
  };

  const resetAll = () => {
    setLearnedMap({});
    localStorage.removeItem('learned_map');
    setIsSettingsOpen(false);
  };

  return (
    <div className="min-h-screen flex flex-col items-center justify-between pb-24 pt-8 px-4 max-w-md mx-auto relative select-none">

      <header className="w-full flex justify-between items-center mb-4">
        <div className="flex items-center gap-2">
          <div className="bg-indigo-600 p-2 rounded-xl text-white shadow-lg shadow-indigo-100">
            <Layers className="w-5 h-5" />
          </div>
          <h1 className="text-xl font-black text-slate-800 tracking-tight">IPA MASTER</h1>
        </div>
        <button 
          onClick={() => setIsSettingsOpen(true)}
          className="p-3 bg-white rounded-2xl shadow-sm border border-slate-100 text-slate-400 hover:text-indigo-600 transition-all hover:shadow-md"
        >
          <Settings className="w-6 h-6" />
        </button>
      </header>

      {activeTab === 'study' ? (
        <main className="w-full flex-grow flex flex-col items-center justify-center gap-6">
          {studyQueue.length > 0 && currentCard ? (
            <div className="w-full relative flex flex-col items-center gap-8">
              <div 
                className="w-full flex justify-center h-[420px] relative group"
                onTouchStart={onTouchStart}
                onTouchMove={onTouchMove}
                onTouchEnd={onTouchEnd}
              >
                {settings.activeFeatures.length === 2 ? (
                  <Flashcard 
                    data={currentCard}
                    promptFeature={settings.promptFeature}
                    maskedFeature={settings.maskedFeature}
                    isFlipped={cardState.isFlipped}
                    onFlip={() => setCardState(p => ({ ...p, isFlipped: !p.isFlipped }))}
                    isQuiz={settings.mode === 'QUIZ'}
                    userInput={cardState.userInput}
                    setUserInput={(v) => setCardState(p => ({ ...p, userInput: v }))}
                    feedback={cardState.feedback}
                    onSubmit={handleQuizSubmit}
                    onMarkStatus={settings.mode === 'FLASHCARD' ? handleMarkStatus : undefined}
                  />
                ) : (
                  <FoldedCard 
                    data={currentCard}
                    promptFeature={settings.promptFeature}
                    maskedFeature={settings.maskedFeature}
                    features={settings.activeFeatures}
                    isQuiz={settings.mode === 'QUIZ'}
                    userInput={cardState.userInput}
                    setUserInput={(v) => setCardState(p => ({ ...p, userInput: v }))}
                    feedback={cardState.feedback}
                    onSubmit={handleQuizSubmit}
                    onMarkStatus={settings.mode === 'FLASHCARD' ? handleMarkStatus : undefined}
                  />
                )}
              </div>

              {/* Navigation Arrows */}
              <div className="flex items-center justify-center gap-8 w-full mt-4">
                <button 
                  onClick={handlePrev}
                  className="p-4 bg-white rounded-full shadow-lg border border-slate-100 text-slate-400 hover:text-indigo-600 transition-all hover:scale-110 active:scale-95"
                  aria-label="Previous card"
                >
                  <ChevronLeft className="w-8 h-8" />
                </button>
                <div className="text-slate-400 font-black text-lg tracking-tighter bg-white px-6 py-2 rounded-full shadow-sm border border-slate-50 min-w-[100px] text-center">
                  {cardState.currentQueueIndex + 1} <span className="opacity-20 mx-1">/</span> {studyQueue.length}
                </div>
                <button 
                  onClick={handleNext}
                  className="p-4 bg-white rounded-full shadow-lg border border-slate-100 text-slate-400 hover:text-indigo-600 transition-all hover:scale-110 active:scale-95"
                  aria-label="Next card"
                >
                  <ChevronRight className="w-8 h-8" />
                </button>
              </div>

              <div className="text-[10px] font-black uppercase tracking-widest text-slate-300 flex items-center gap-2 opacity-50">
                <MoveHorizontal className="w-3 h-3" />
                Swipe or use arrows
              </div>
            </div>
          ) : (
            <div className="text-center p-12 bg-white rounded-[3rem] shadow-xl border border-slate-100 w-full animate-in fade-in zoom-in">
              <RotateCcw className="w-16 h-16 text-indigo-500 mx-auto mb-6" />
              <h2 className="text-2xl font-black text-slate-800 mb-2">Queue Clear!</h2>
              <p className="text-slate-400 text-sm mb-8 leading-relaxed">You've mastered all cards in this session. Great job!</p>
              <button 
                onClick={resetAll}
                className="w-full py-4 bg-indigo-600 text-white rounded-2xl font-black text-lg shadow-xl shadow-indigo-100 active:scale-95 transition-all"
              >
                RESET PROGRESS
              </button>
            </div>
          )}
        </main>
      ) : (
        <main className="w-full flex-grow flex flex-col items-center justify-start py-8 gap-8 animate-in fade-in duration-300">
          <div className="bg-white p-8 rounded-[2.5rem] w-full border border-slate-100 shadow-xl shadow-slate-100">
            <div className="flex items-center gap-3 mb-6">
              <Microscope className="w-6 h-6 text-indigo-600" />
              <h2 className="text-xl font-black text-slate-800">IPA LAB</h2>
            </div>
            <p className="text-slate-500 text-sm mb-6 leading-relaxed font-medium">
              Enter symbols to synthesize sound (Future Development). For now, it plays the standard character sound.
            </p>
            <div className="bg-slate-50 p-4 rounded-3xl shadow-inner border border-slate-200 mb-6">
              <input 
                type="text"
                value={labInput}
                onChange={(e) => setLabInput(e.target.value)}
                placeholder="Type symbols..."
                className="w-full bg-transparent text-3xl font-bold text-slate-900 outline-none ipa-font placeholder:text-slate-200 text-center"
              />
            </div>
            <button 
              onClick={() => playSynthesizedWord(labInput)}
              disabled={!labInput.trim()}
              className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black flex items-center justify-center gap-3 shadow-xl shadow-indigo-100 disabled:opacity-50 hover:bg-indigo-700 transition-all active:scale-95"
            >
              <Music className="w-5 h-5" />
              PLAY SYNTHESIS
            </button>
          </div>
        </main>
      )}

      <nav className="fixed bottom-8 left-1/2 -translate-x-1/2 bg-slate-900/95 backdrop-blur-xl rounded-[2.5rem] px-10 py-5 flex gap-10 items-center shadow-2xl z-40 border border-white/10">
        <button 
          onClick={() => setActiveTab('study')}
          className={`flex flex-col items-center gap-1.5 transition-all ${activeTab === 'study' ? 'text-indigo-400 scale-110' : 'text-slate-500 hover:text-slate-300'}`}
        >
          <Layers className="w-6 h-6" />
          <span className="text-[10px] font-black uppercase tracking-widest">Study</span>
        </button>
        <div className="w-px h-6 bg-slate-800"></div>
        <button 
          onClick={() => setActiveTab('lab')}
          className={`flex flex-col items-center gap-1.5 transition-all ${activeTab === 'lab' ? 'text-indigo-400 scale-110' : 'text-slate-500 hover:text-slate-300'}`}
        >
          <Microscope className="w-6 h-6" />
          <span className="text-[10px] font-black uppercase tracking-widest">Lab</span>
        </button>
      </nav>

      {isSettingsOpen && (
        <SettingsOverlay 
          settings={settings}
          onUpdate={setSettings}
          onClose={() => setIsSettingsOpen(false)}
          onReset={resetAll}
        />
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { IPAFeature, IPACardData, AppSettings, CardState, LearningStatus } from './types';
import { ipaDataset } from './data/ipaData';
import { Flashcard } from './components/Flashcard';
import { FoldedCard } from './components/FoldedCard';
import { SettingsOverlay } from './components/SettingsOverlay';
import { Settings, Layers, Microscope, Music, MoveHorizontal, RotateCcw, ChevronLeft, ChevronRight } from 'lucide-react';
import { playIPASound, playSynthesizedWord } from './services/audioService';

const App: React.FC = () => {
  const [settings, setSettings] = useState<AppSettings>({
    activeFeatures: [IPAFeature.SYMBOL, IPAFeature.LABEL],
    promptFeature: IPAFeature.SYMBOL,
    maskedFeature: IPAFeature.LABEL,
    mode: 'FLASHCARD'
  });

  const [learnedMap, setLearnedMap] = useState<Record<string, LearningStatus>>(() => {
    const saved = localStorage.getItem('learned_map');
    return saved ? JSON.parse(saved) : {};
  });

  const [studyQueue, setStudyQueue] = useState<string[]>([]);

  const [cardState, setCardState] = useState<CardState>({
    currentQueueIndex: 0,
    isFlipped: false,
    userInput: '',
    feedback: 'none'
  });

  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [activeTab, setActiveTab] = useState<'study' | 'lab'>('study');
  const [labInput, setLabInput] = useState('');

  const touchStart = useRef<number | null>(null);
  const touchEnd = useRef<number | null>(null);

  // Initialize queue
  useEffect(() => {
    const freshQueue = ipaDataset
      .filter(card => learnedMap[card.id] !== LearningStatus.REMEMBERED)
      .map(card => card.id);

    if (freshQueue.length > 0) {
      freshQueue.sort(() => Math.random() - 0.5);
      setStudyQueue(freshQueue);
    } else {
      setStudyQueue([]);
    }
    setCardState(prev => ({ ...prev, currentQueueIndex: 0, isFlipped: false, userInput: '', feedback: 'none' }));
  }, [learnedMap, settings.mode]);

  useEffect(() => {
    localStorage.setItem('learned_map', JSON.stringify(learnedMap));
  }, [learnedMap]);

  const handleNext = useCallback(() => {
    if (studyQueue.length === 0) return;
    setCardState(prev => ({
      ...prev,
      currentQueueIndex: (prev.currentQueueIndex + 1) % studyQueue.length,
      isFlipped: false,
      userInput: '',
      feedback: 'none'
    }));
  }, [studyQueue]);

  const handlePrev = useCallback(() => {
    if (studyQueue.length === 0) return;
    setCardState(prev => ({
      ...prev,
      currentQueueIndex: (prev.currentQueueIndex - 1 + studyQueue.length) % studyQueue.length,
      isFlipped: false,
      userInput: '',
      feedback: 'none'
    }));
  }, [studyQueue]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.target instanceof HTMLInputElement) return;
      if (e.key === 'ArrowRight') handleNext();
      if (e.key === 'ArrowLeft') handlePrev();
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleNext, handlePrev]);

  const onTouchStart = (e: React.TouchEvent) => {
    touchEnd.current = null;
    touchStart.current = e.targetTouches[0].clientX;
  };

  const onTouchMove = (e: React.TouchEvent) => {
    touchEnd.current = e.targetTouches[0].clientX;
  };

  const onTouchEnd = () => {
    if (!touchStart.current || !touchEnd.current) return;
    const distance = touchStart.current - touchEnd.current;
    if (distance > 50) handleNext();
    if (distance < -50) handlePrev();
  };

  const currentCardId = studyQueue[cardState.currentQueueIndex];
  const currentCard = ipaDataset.find(c => c.id === currentCardId);

  const handleMarkStatus = (status: LearningStatus) => {
    if (!currentCard) return;
    if (status === LearningStatus.REMEMBERED) {
      setLearnedMap(prev => ({ ...prev, [currentCard.id]: LearningStatus.REMEMBERED }));
    } else {
      handleNext();
    }
  };

  const handleQuizSubmit = (input: string) => {
    if (!currentCard) return;
    const targetFeature = settings.maskedFeature;
    let isCorrect = false;

    const sanitizedInput = input.toLowerCase().trim();
    if (targetFeature === IPAFeature.SYMBOL) isCorrect = sanitizedInput === currentCard.symbol.toLowerCase();
    else if (targetFeature === IPAFeature.LABEL) isCorrect = currentCard.label.toLowerCase().includes(sanitizedInput);
    else if (targetFeature === IPAFeature.WORDS) isCorrect = currentCard.words.some(w => w.toLowerCase() === sanitizedInput);

    if (isCorrect) {
      setCardState(prev => ({ ...prev, feedback: 'correct', isFlipped: true }));
      setTimeout(() => {
        setLearnedMap(prev => ({ ...prev, [currentCard.id]: LearningStatus.REMEMBERED }));
      }, 1000);
    } else {
      setCardState(prev => ({ ...prev, feedback: 'incorrect', isFlipped: true }));
      setStudyQueue(prev => [...prev, currentCard.id]);
    }
  };

  const resetAll = () => {
    setLearnedMap({});
    localStorage.removeItem('learned_map');
    setIsSettingsOpen(false);
  };

  return (
    <div className="min-h-screen flex flex-col items-center justify-between pb-24 pt-8 px-4 max-w-md mx-auto relative select-none">

      <header className="w-full flex justify-between items-center mb-4">
        <div className="flex items-center gap-2">
          <div className="bg-primary p-2 rounded-xl text-white shadow-lg shadow-primary/20">
            <Layers className="w-5 h-5" />
          </div>
          <h1 className="text-xl font-black text-slate-800 tracking-tight">IPA MASTER</h1>
        </div>
        <button 
          onClick={() => setIsSettingsOpen(true)}
          className="p-3 bg-white rounded-2xl shadow-sm border border-slate-100 text-slate-400 hover:text-primary transition-all hover:shadow-md"
        >
          <Settings className="w-6 h-6" />
        </button>
      </header>

      {activeTab === 'study' ? (
        <main className="w-full flex-grow flex flex-col items-center justify-center gap-6">
          {studyQueue.length > 0 && currentCard ? (
            <div className="w-full relative flex flex-col items-center gap-8">
              <div 
                className="w-full flex justify-center h-[420px] relative group"
                onTouchStart={onTouchStart}
                onTouchMove={onTouchMove}
                onTouchEnd={onTouchEnd}
              >
                {settings.activeFeatures.length === 2 ? (
                  <Flashcard 
                    data={currentCard}
                    promptFeature={settings.promptFeature}
                    maskedFeature={settings.maskedFeature}
                    isFlipped={cardState.isFlipped}
                    onFlip={() => setCardState(p => ({ ...p, isFlipped: !p.isFlipped }))}
                    isQuiz={settings.mode === 'QUIZ'}
                    userInput={cardState.userInput}
                    setUserInput={(v) => setCardState(p => ({ ...p, userInput: v }))}
                    feedback={cardState.feedback}
                    onSubmit={handleQuizSubmit}
                    onMarkStatus={settings.mode === 'FLASHCARD' ? handleMarkStatus : undefined}
                  />
                ) : (
                  <FoldedCard 
                    data={currentCard}
                    promptFeature={settings.promptFeature}
                    maskedFeature={settings.maskedFeature}
                    features={settings.activeFeatures}
                    isQuiz={settings.mode === 'QUIZ'}
                    userInput={cardState.userInput}
                    setUserInput={(v) => setCardState(p => ({ ...p, userInput: v }))}
                    feedback={cardState.feedback}
                    onSubmit={handleQuizSubmit}
                    onMarkStatus={settings.mode === 'FLASHCARD' ? handleMarkStatus : undefined}
                  />
                )}
              </div>

              <div className="flex items-center justify-center gap-8 w-full mt-4">
                <button 
                  onClick={handlePrev}
                  className="p-4 bg-white rounded-full shadow-lg border border-slate-100 text-slate-400 hover:text-primary transition-all hover:scale-110 active:scale-95"
                >
                  <ChevronLeft className="w-8 h-8" />
                </button>
                <div className="text-slate-400 font-black text-lg tracking-tighter bg-white px-6 py-2 rounded-full shadow-sm border border-slate-50 min-w-[100px] text-center">
                  {cardState.currentQueueIndex + 1} <span className="opacity-20 mx-1">/</span> {studyQueue.length}
                </div>
                <button 
                  onClick={handleNext}
                  className="p-4 bg-white rounded-full shadow-lg border border-slate-100 text-slate-400 hover:text-primary transition-all hover:scale-110 active:scale-95"
                >
                  <ChevronRight className="w-8 h-8" />
                </button>
              </div>

              <div className="text-[10px] font-black uppercase tracking-widest text-slate-300 flex items-center gap-2 opacity-50">
                <MoveHorizontal className="w-3 h-3" />
                Swipe or use arrows
              </div>
            </div>
          ) : (
            <div className="text-center p-12 bg-white rounded-[3rem] shadow-xl border border-slate-100 w-full animate-in fade-in zoom-in">
              <RotateCcw className="w-16 h-16 text-primary mx-auto mb-6 animate-spin-slow" />
              <h2 className="text-2xl font-black text-slate-800 mb-2">Queue Clear!</h2>
              <p className="text-slate-400 text-sm mb-8 leading-relaxed">You've mastered all cards in this session. Great job!</p>
              <button 
                onClick={resetAll}
                className="w-full py-4 bg-primary text-white rounded-2xl font-black text-lg shadow-xl shadow-primary/20 active:scale-95 transition-all"
              >
                RESET PROGRESS
              </button>
            </div>
          )}
        </main>
      ) : (
        <main className="w-full flex-grow flex flex-col items-center justify-start py-8 gap-8 animate-in fade-in duration-300">
          <div className="bg-white p-8 rounded-[2.5rem] w-full border border-slate-100 shadow-xl shadow-slate-100">
            <div className="flex items-center gap-3 mb-6">
              <Microscope className="w-6 h-6 text-secondary" />
              <h2 className="text-xl font-black text-slate-800">IPA LAB</h2>
            </div>
            <p className="text-slate-500 text-sm mb-6 leading-relaxed font-medium">
              Enter symbols to synthesize sound (Future Development). For now, it plays the standard character sound.
            </p>
            <div className="bg-slate-50 p-4 rounded-3xl shadow-inner border border-slate-200 mb-6">
              <input 
                type="text"
                value={labInput}
                onChange={(e) => setLabInput(e.target.value)}
                placeholder="Type symbols..."
                className="w-full bg-transparent text-3xl font-bold text-slate-900 outline-none ipa-font placeholder:text-slate-200 text-center"
              />
            </div>
            <button 
              onClick={() => playSynthesizedWord(labInput)}
              disabled={!labInput.trim()}
              className="w-full py-5 bg-secondary text-white rounded-2xl font-black flex items-center justify-center gap-3 shadow-xl shadow-secondary/20 disabled:opacity-50 hover:bg-secondary/90 transition-all active:scale-95"
            >
              <Music className="w-5 h-5" />
              PLAY SYNTHESIS
            </button>
          </div>
        </main>
      )}

      <nav className="fixed bottom-8 left-1/2 -translate-x-1/2 bg-slate-900/95 backdrop-blur-xl rounded-[2.5rem] px-10 py-5 flex gap-10 items-center shadow-2xl z-40 border border-white/10">
        <button 
          onClick={() => setActiveTab('study')}
          className={`flex flex-col items-center gap-1.5 transition-all ${activeTab === 'study' ? 'text-primary scale-110' : 'text-slate-500 hover:text-slate-300'}`}
        >
          <Layers className="w-6 h-6" />
          <span className="text-[10px] font-black uppercase tracking-widest">Study</span>
        </button>
        <div className="w-px h-6 bg-slate-800"></div>
        <button 
          onClick={() => setActiveTab('lab')}
          className={`flex flex-col items-center gap-1.5 transition-all ${activeTab === 'lab' ? 'text-secondary scale-110' : 'text-slate-500 hover:text-slate-300'}`}
        >
          <Microscope className="w-6 h-6" />
          <span className="text-[10px] font-black uppercase tracking-widest">Lab</span>
        </button>
      </nav>

      {isSettingsOpen && (
        <SettingsOverlay 
          settings={settings}
          onUpdate={setSettings}
          onClose={() => setIsSettingsOpen(false)}
          onReset={resetAll}
        />
      )}
    </div>
  );
};

export default App;

import React from 'react';
import { IPAFeature, IPACardData, LearningStatus } from '../types';
import { Volume2, CheckCircle, XCircle, HelpCircle, Check, X } from 'lucide-react';
import { playIPASound } from '../services/audioService';

interface FlashcardProps {
  data: IPACardData;
  promptFeature: IPAFeature;
  maskedFeature: IPAFeature;
  isFlipped: boolean;
  onFlip: () => void;
  isQuiz: boolean;
  userInput: string;
  setUserInput: (val: string) => void;
  feedback: 'none' | 'correct' | 'incorrect';
  onSubmit: (val: string) => void;
  onMarkStatus?: (status: LearningStatus) => void;
}

const FeatureContent: React.FC<{ feature: IPAFeature; data: IPACardData }> = ({ feature, data }) => {
  switch (feature) {
    case IPAFeature.SYMBOL:
      return <div className="ipa-font text-8xl font-bold text-slate-800">{data.symbol}</div>;
    case IPAFeature.LABEL:
      return <div className="text-2xl font-semibold text-slate-700 text-center px-4 leading-snug">{data.label}</div>;
    case IPAFeature.WORDS:
      return (
        <div className="flex flex-col items-center gap-2">
          <span className="text-sm uppercase tracking-widest text-slate-400 mb-2 font-bold">Examples</span>
          {data.words.map((w, i) => (
            <span key={i} className="text-xl font-medium text-slate-700">{w}</span>
          ))}
        </div>
      );
    case IPAFeature.SOUND:
      return (
        <button 
          onClick={(e) => { e.stopPropagation(); playIPASound(data.id, data.symbol); }}
          className="p-8 bg-primary/10 rounded-full hover:bg-primary/20 transition-colors group"
        >
          <Volume2 className="w-16 h-16 text-primary group-hover:scale-110 transition-transform" />
        </button>
      );
    default:
      return null;
  }
};

export const Flashcard: React.FC<FlashcardProps> = ({ 
  data, promptFeature, maskedFeature, isFlipped, onFlip, isQuiz, userInput, setUserInput, feedback, onSubmit, onMarkStatus 
}) => {
  const handleQuizSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSubmit(userInput);
  };

  return (
    <div className="w-full max-w-sm h-[420px] perspective-1000 cursor-pointer" onClick={onFlip}>
      <div className={`relative w-full h-full transition-transform duration-700 preserve-3d ${isFlipped ? 'rotate-y-180' : ''}`}>

        {/* Front */}
        <div className="absolute inset-0 bg-white rounded-3xl shadow-xl flex flex-col items-center justify-center border border-slate-100 backface-hidden">
          <FeatureContent feature={promptFeature} data={data} />
          <div className="absolute bottom-4 right-6 text-slate-300 text-[10px] font-black uppercase tracking-widest">{promptFeature}</div>
        </div>

        {/* Back */}
        <div className="absolute inset-0 bg-white rounded-3xl shadow-xl flex flex-col items-center justify-center border border-slate-100 backface-hidden rotate-y-180">
          {isQuiz && !isFlipped ? (
            <div className="p-6 w-full flex flex-col items-center gap-4" onClick={(e) => e.stopPropagation()}>
              <h3 className="text-sm font-bold text-slate-400 uppercase tracking-widest">Identify {maskedFeature.toLowerCase()}</h3>
              <form onSubmit={handleQuizSubmit} className="w-full">
                <input
                  autoFocus
                  type="text"
                  value={userInput}
                  onChange={(e) => setUserInput(e.target.value)}
                  className="w-full px-4 py-3 rounded-xl border-2 border-slate-200 focus:border-primary outline-none text-center text-xl font-bold"
                  placeholder="???"
                />
                <button 
                  type="submit"
                  className="w-full mt-4 bg-primary text-white py-3 rounded-xl font-bold hover:bg-primary/90 transition-colors shadow-lg"
                >
                  CHECK
                </button>
              </form>
            </div>
          ) : (
            <div className="flex flex-col items-center gap-6">
              {feedback === 'correct' && <div className="text-green-500 flex items-center gap-2 font-bold animate-bounce"><CheckCircle className="w-6 h-6" /> CORRECT</div>}
              {feedback === 'incorrect' && <div className="text-red-500 flex items-center gap-2 font-bold"><XCircle className="w-6 h-6" /> INCORRECT</div>}

              <FeatureContent feature={maskedFeature} data={data} />

              {onMarkStatus && isFlipped && (
                <div className="flex gap-4 mt-4" onClick={(e) => e.stopPropagation()}>
                  <button 
                    onClick={() => onMarkStatus(LearningStatus.NO)}
                    className="p-3 bg-red-50 text-red-500 rounded-2xl hover:bg-red-100 transition-colors flex flex-col items-center gap-1"
                  >
                    <X className="w-6 h-6" />
                    <span className="text-[10px] font-bold">NO</span>
                  </button>
                  <button 
                    onClick={() => onMarkStatus(LearningStatus.MAYBE)}
                    className="p-3 bg-secondary/10 text-secondary rounded-2xl hover:bg-secondary/20 transition-colors flex flex-col items-center gap-1"
                  >
                    <HelpCircle className="w-6 h-6" />
                    <span className="text-[10px] font-bold">MAYBE</span>
                  </button>
                  <button 
                    onClick={() => onMarkStatus(LearningStatus.REMEMBERED)}
                    className="p-3 bg-green-50 text-green-500 rounded-2xl hover:bg-green-100 transition-colors flex flex-col items-center gap-1"
                  >
                    <Check className="w-6 h-6" />
                    <span className="text-[10px] font-bold">YES</span>
                  </button>
                </div>
              )}
            </div>
          )}
          <div className="absolute bottom-4 right-6 text-slate-300 text-[10px] font-black uppercase tracking-widest">{maskedFeature}</div>
        </div>

      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { IPAFeature, IPACardData, LearningStatus } from '../types';
import { Volume2, ChevronRight, ChevronLeft, CheckCircle, XCircle, Check, X, HelpCircle } from 'lucide-react';
import { playIPASound } from '../services/audioService';

interface FoldedCardProps {
  data: IPACardData;
  promptFeature: IPAFeature;
  maskedFeature: IPAFeature;
  features: IPAFeature[];
  isQuiz?: boolean;
  userInput: string;
  setUserInput: (val: string) => void;
  feedback: 'none' | 'correct' | 'incorrect';
  onSubmit: (val: string) => void;
  onMarkStatus?: (status: LearningStatus) => void;
}

const FeatureIcon: React.FC<{ feature: IPAFeature }> = ({ feature }) => {
  switch (feature) {
    case IPAFeature.SYMBOL: return <span className="text-lg font-bold">Ω</span>;
    case IPAFeature.LABEL: return <span className="text-lg font-bold">abc</span>;
    case IPAFeature.WORDS: return <span className="text-lg font-bold">""</span>;
    case IPAFeature.SOUND: return <Volume2 className="w-5 h-5" />;
    default: return null;
  }
};

const FeatureDisplay: React.FC<{ feature: IPAFeature; data: IPACardData }> = ({ feature, data }) => {
  switch (feature) {
    case IPAFeature.SYMBOL:
      return <div className="ipa-font text-7xl font-bold text-slate-800">{data.symbol}</div>;
    case IPAFeature.LABEL:
      return <div className="text-xl font-semibold text-slate-700 text-center px-4 leading-relaxed">{data.label}</div>;
    case IPAFeature.WORDS:
      return (
        <div className="flex flex-wrap justify-center gap-3">
          {data.words.map((w, i) => (
            <span key={i} className="px-4 py-2 bg-slate-50 border border-slate-100 rounded-full text-slate-600 font-medium">{w}</span>
          ))}
        </div>
      );
    case IPAFeature.SOUND:
      return (
        <button 
          onClick={(e) => { e.stopPropagation(); playIPASound(data.id, data.symbol); }}
          className="p-6 bg-primary rounded-full text-white shadow-lg hover:bg-primary/90 transition-all active:scale-95"
        >
          <Volume2 className="w-10 h-10" />
        </button>
      );
    default: return null;
  }
};

export const FoldedCard: React.FC<FoldedCardProps> = ({ 
  data, promptFeature, maskedFeature, features, isQuiz, userInput, setUserInput, feedback, onSubmit, onMarkStatus 
}) => {
  const [activeSurface, setActiveSurface] = useState(0);

  useEffect(() => {
    const promptIdx = features.indexOf(promptFeature);
    if (promptIdx !== -1) setActiveSurface(promptIdx);
  }, [promptFeature, features]);

  const nextSurface = () => setActiveSurface((s) => (s + 1) % features.length);
  const prevSurface = () => setActiveSurface((s) => (s - 1 + features.length) % features.length);

  const isCurrentSurfaceMasked = isQuiz && features[activeSurface] === maskedFeature && feedback === 'none';

  const handleQuizSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSubmit(userInput);
  };

  return (
    <div 
      className="w-full max-w-sm h-[420px] relative flex flex-col items-center justify-center bg-white rounded-3xl shadow-2xl border border-slate-100 overflow-hidden cursor-pointer"
      onClick={nextSurface}
    >
      <div className="absolute top-0 right-0 w-16 h-16 bg-slate-50 -rotate-45 translate-x-8 -translate-y-8 shadow-inner border-b border-slate-200"></div>

      <div className="absolute top-6 left-1/2 -translate-x-1/2 flex gap-2">
        {features.map((_, i) => (
          <div 
            key={i} 
            className={`h-2 rounded-full transition-all duration-300 ${i === activeSurface ? 'w-8 bg-primary/40' : 'w-2 bg-slate-200'}`}
          />
        ))}
      </div>

      <div className="flex flex-col items-center justify-center p-8 text-center w-full" key={activeSurface}>
        <div className="text-xs font-bold text-slate-300 uppercase tracking-widest mb-6 flex items-center gap-2">
          <FeatureIcon feature={features[activeSurface]} />
          {features[activeSurface]}
        </div>

        {isCurrentSurfaceMasked ? (
          <div className="w-full max-w-[240px]" onClick={(e) => e.stopPropagation()}>
            <form onSubmit={handleQuizSubmit} className="flex flex-col gap-4">
               <input
                autoFocus
                type="text"
                value={userInput}
                onChange={(e) => setUserInput(e.target.value)}
                className="w-full px-4 py-3 rounded-xl border-2 border-slate-200 focus:border-primary outline-none text-center text-xl font-bold"
                placeholder="Identify..."
              />
              <button 
                type="submit"
                className="bg-primary text-white py-3 rounded-xl font-bold hover:bg-primary/90 transition-colors shadow-lg shadow-primary/20"
              >
                CHECK
              </button>
            </form>
          </div>
        ) : (
          <div className="animate-in fade-in zoom-in duration-300 flex flex-col items-center">
            {isQuiz && features[activeSurface] === maskedFeature && (
              <div className="mb-4 flex justify-center">
                {feedback === 'correct' ? <CheckCircle className="text-green-500 w-8 h-8" /> : <XCircle className="text-red-500 w-8 h-8" />}
              </div>
            )}
            <FeatureDisplay feature={features[activeSurface]} data={data} />

            {onMarkStatus && (
              <div className="flex gap-4 mt-8" onClick={(e) => e.stopPropagation()}>
                <button 
                  onClick={() => onMarkStatus(LearningStatus.NO)} 
                  className="p-3 bg-red-50 text-red-500 rounded-xl hover:bg-red-100 transition-all"
                >
                  <X className="w-6 h-6"/>
                </button>
                <button 
                  onClick={() => onMarkStatus(LearningStatus.MAYBE)} 
                  className="p-3 bg-secondary/10 text-secondary rounded-xl hover:bg-secondary/20 transition-all"
                >
                  <HelpCircle className="w-6 h-6"/>
                </button>
                <button 
                  onClick={() => onMarkStatus(LearningStatus.REMEMBERED)} 
                  className="p-3 bg-green-50 text-green-500 rounded-xl hover:bg-green-100 transition-all"
                >
                  <Check className="w-6 h-6"/>
                </button>
              </div>
            )}
          </div>
        )}
      </div>

      <button 
        onClick={(e) => { e.stopPropagation(); prevSurface(); }} 
        className="absolute left-2 top-1/2 -translate-y-1/2 p-2 text-slate-200 hover:text-primary transition-colors"
      >
        <ChevronLeft className="w-8 h-8" />
      </button>
      <button 
        onClick={(e) => { e.stopPropagation(); nextSurface(); }} 
        className="absolute right-2 top-1/2 -translate-y-1/2 p-2 text-slate-200 hover:text-primary transition-colors"
      >
        <ChevronRight className="w-8 h-8" />
      </button>

      <div className="absolute bottom-0 inset-x-0 h-12 flex">
        {features.map((feature, i) => (
          <button
            key={i}
            onClick={(e) => { e.stopPropagation(); setActiveSurface(i); }}
            className={`flex-1 flex items-center justify-center border-t transition-all ${
              i === activeSurface 
                ? 'bg-primary/5 text-primary border-primary/20 font-black text-xs' 
                : 'bg-white text-slate-300 border-slate-50 text-[10px]'
            }`}
          >
            <FeatureIcon feature={feature} />
          </button>
        ))}
      </div>
    </div>
  );
};

import React from 'react';
import { IPAFeature, AppSettings, StudyMode } from '../types';
import { X, Check, EyeOff, Eye, RotateCcw } from 'lucide-react';

interface SettingsOverlayProps {
  settings: AppSettings;
  onUpdate: (settings: AppSettings) => void;
  onClose: () => void;
  onReset: () => void;
}

export const SettingsOverlay: React.FC<SettingsOverlayProps> = ({ settings, onUpdate, onClose, onReset }) => {
  const toggleFeature = (feature: IPAFeature) => {
    let newFeatures = [...settings.activeFeatures];
    if (newFeatures.includes(feature)) {
      if (newFeatures.length > 2) {
        newFeatures = newFeatures.filter(f => f !== feature);
      }
    } else {
      newFeatures.push(feature);
    }

    let nextPrompt = settings.promptFeature;
    let nextMasked = settings.maskedFeature;

    if (!newFeatures.includes(nextPrompt)) {
      nextPrompt = newFeatures[0];
    }

    if (!newFeatures.includes(nextMasked) || nextMasked === IPAFeature.SOUND) {
      nextMasked = newFeatures.find(f => f !== IPAFeature.SOUND && f !== nextPrompt) || newFeatures.find(f => f !== IPAFeature.SOUND) || newFeatures[0];
    }

    onUpdate({ ...settings, activeFeatures: newFeatures, promptFeature: nextPrompt, maskedFeature: nextMasked });
  };

  const setMode = (mode: StudyMode) => {
    onUpdate({ ...settings, mode });
  };

  const setPrompt = (f: IPAFeature) => {
    let nextMasked = settings.maskedFeature;
    if (f === nextMasked) {
      nextMasked = settings.activeFeatures.find(feat => feat !== f && feat !== IPAFeature.SOUND) || settings.activeFeatures[0];
    }
    onUpdate({ ...settings, promptFeature: f, maskedFeature: nextMasked });
  };

  const setMasked = (f: IPAFeature) => {
    if (f === IPAFeature.SOUND) return; 
    let nextPrompt = settings.promptFeature;
    if (f === nextPrompt) {
      nextPrompt = settings.activeFeatures.find(feat => feat !== f) || settings.activeFeatures[0];
    }
    onUpdate({ ...settings, maskedFeature: f, promptFeature: nextPrompt });
  };

  return (
    <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-50 flex items-end sm:items-center justify-center p-4">
      <div className="bg-white w-full max-w-md rounded-[2.5rem] p-8 shadow-2xl animate-in slide-in-from-bottom duration-300 max-h-[90vh] overflow-y-auto">
        <div className="flex justify-between items-center mb-8">
          <h2 className="text-2xl font-black text-slate-800 tracking-tight">STUDY SETUP</h2>
          <button onClick={onClose} className="p-2 bg-slate-100 rounded-full hover:bg-slate-200 transition-colors">
            <X className="w-6 h-6 text-slate-600" />
          </button>
        </div>

        <div className="space-y-8">
          <section>
            <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-4">Study Mode</h3>
            <div className="grid grid-cols-2 gap-4">
              {(['FLASHCARD', 'QUIZ'] as StudyMode[]).map((m) => (
                <button
                  key={m}
                  onClick={() => setMode(m)}
                  className={`py-3 rounded-2xl font-bold transition-all border-2 ${
                    settings.mode === m 
                      ? 'bg-primary border-primary text-white shadow-lg shadow-primary/20' 
                      : 'bg-white border-slate-100 text-slate-400'
                  }`}
                >
                  {m}
                </button>
              ))}
            </div>
          </section>

          <section>
            <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-4">Features in Card</h3>
            <div className="grid grid-cols-2 gap-3">
              {Object.values(IPAFeature).map((feature) => {
                const isActive = settings.activeFeatures.includes(feature);
                return (
                  <button
                    key={feature}
                    onClick={() => toggleFeature(feature)}
                    className={`flex items-center justify-between p-3 rounded-2xl border-2 transition-all ${
                      isActive ? 'bg-primary/10 border-primary/20 text-primary' : 'bg-white border-slate-50 text-slate-300'
                    }`}
                  >
                    <span className="font-bold text-sm">{feature}</span>
                    {isActive && <Check className="w-4 h-4 text-primary" />}
                  </button>
                );
              })}
            </div>
          </section>

          <div className="grid grid-cols-2 gap-6">
            <section>
              <h3 className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-3 flex items-center gap-2">
                <Eye className="w-3 h-3 text-primary" /> Prompt
              </h3>
              <div className="flex flex-col gap-2">
                {settings.activeFeatures.map((f) => (
                  <button
                    key={f}
                    onClick={() => setPrompt(f)}
                    className={`p-2 rounded-xl border-2 text-xs font-bold transition-all ${
                      settings.promptFeature === f ? 'bg-primary/10 border-primary/20 text-primary' : 'bg-white border-slate-50 text-slate-300'
                    }`}
                  >
                    {f}
                  </button>
                ))}
              </div>
            </section>

            <section>
              <h3 className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-3 flex items-center gap-2">
                <EyeOff className="w-3 h-3 text-secondary" /> Answer
              </h3>
              <div className="flex flex-col gap-2">
                {settings.activeFeatures
                  .filter(f => f !== IPAFeature.SOUND)
                  .map((f) => (
                  <button
                    key={f}
                    onClick={() => setMasked(f)}
                    className={`p-2 rounded-xl border-2 text-xs font-bold transition-all ${
                      settings.maskedFeature === f ? 'bg-secondary/10 border-secondary/20 text-secondary' : 'bg-white border-slate-50 text-slate-300'
                    }`}
                  >
                    {f}
                  </button>
                ))}
              </div>
            </section>
          </div>

          <div className="pt-4 border-t border-slate-50 flex flex-col gap-4">
            <button 
              onClick={onReset}
              className="w-full py-4 border-2 border-slate-100 text-slate-400 rounded-2xl font-black text-sm flex items-center justify-center gap-2 hover:bg-slate-50"
            >
              <RotateCcw className="w-4 h-4" /> RESET ALL PROGRESS
            </button>
            <button 
              onClick={onClose}
              className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black text-lg hover:bg-slate-800 transition-all shadow-xl shadow-slate-200"
            >
              START STUDYING
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

const CACHE_NAME = 'ipa-master-v1';
const ASSETS = [
  '/',
  '/index.html',
  '/index.tsx',
  '/manifest.json'
];

self.addEventListener('install', (event) => {
  event.waitUntil(
    caches.open(CACHE_NAME).then((cache) => cache.addAll(ASSETS))
  );
});

self.addEventListener('fetch', (event) => {
  event.respondWith(
    caches.match(event.request).then((response) => {
      return response || fetch(event.request);
    })
  );
});

