import React from 'react';
import { IPAFeature, AppSettings, StudyMode } from '../types';
import { X, Check, EyeOff, Eye, RotateCcw, Download } from 'lucide-react';

interface SettingsOverlayProps {
  settings: AppSettings;
  onUpdate: (settings: AppSettings) => void;
  onClose: () => void;
  onReset: () => void;
  onInstall?: () => void;
}

export const SettingsOverlay: React.FC<SettingsOverlayProps> = ({ settings, onUpdate, onClose, onReset, onInstall }) => {
  const toggleFeature = (feature: IPAFeature) => {
    let newFeatures = [...settings.activeFeatures];
    if (newFeatures.includes(feature)) {
      if (newFeatures.length > 2) {
        newFeatures = newFeatures.filter(f => f !== feature);
      }
    } else {
      newFeatures.push(feature);
    }

    let nextPrompt = settings.promptFeature;
    let nextMasked = settings.maskedFeature;

    if (!newFeatures.includes(nextPrompt)) {
      nextPrompt = newFeatures[0];
    }

    if (!newFeatures.includes(nextMasked) || nextMasked === IPAFeature.SOUND) {
      nextMasked = newFeatures.find(f => f !== IPAFeature.SOUND && f !== nextPrompt) || newFeatures.find(f => f !== IPAFeature.SOUND) || newFeatures[0];
    }

    onUpdate({ ...settings, activeFeatures: newFeatures, promptFeature: nextPrompt, maskedFeature: nextMasked });
  };

  const setMode = (mode: StudyMode) => {
    onUpdate({ ...settings, mode });
  };

  const setPrompt = (f: IPAFeature) => {
    let nextMasked = settings.maskedFeature;
    if (f === nextMasked) {
      nextMasked = settings.activeFeatures.find(feat => feat !== f && feat !== IPAFeature.SOUND) || settings.activeFeatures[0];
    }
    onUpdate({ ...settings, promptFeature: f, maskedFeature: nextMasked });
  };

  const setMasked = (f: IPAFeature) => {
    if (f === IPAFeature.SOUND) return; 
    let nextPrompt = settings.promptFeature;
    if (f === nextPrompt) {
      nextPrompt = settings.activeFeatures.find(feat => feat !== f) || settings.activeFeatures[0];
    }
    onUpdate({ ...settings, maskedFeature: f, promptFeature: nextPrompt });
  };

  return (
    <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-50 flex items-end sm:items-center justify-center p-4">
      <div className="bg-white w-full max-w-md rounded-[2.5rem] p-8 shadow-2xl animate-in slide-in-from-bottom duration-300 max-h-[90vh] overflow-y-auto">
        <div className="flex justify-between items-center mb-8">
          <h2 className="text-2xl font-black text-slate-800 tracking-tight">STUDY SETUP</h2>
          <button onClick={onClose} className="p-2 bg-slate-100 rounded-full hover:bg-slate-200 transition-colors">
            <X className="w-6 h-6 text-slate-600" />
          </button>
        </div>

        <div className="space-y-8">
          {onInstall && (
            <button 
              onClick={onInstall}
              className="w-full py-4 bg-secondary text-white rounded-2xl font-black text-sm flex items-center justify-center gap-3 shadow-xl shadow-secondary/20 border-2 border-secondary/20 animate-pulse"
            >
              <Download className="w-5 h-5" /> INSTALL TO HOME SCREEN
            </button>
          )}

          <section>
            <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-4">Study Mode</h3>
            <div className="grid grid-cols-2 gap-4">
              {(['FLASHCARD', 'QUIZ'] as StudyMode[]).map((m) => (
                <button
                  key={m}
                  onClick={() => setMode(m)}
                  className={`py-3 rounded-2xl font-bold transition-all border-2 ${
                    settings.mode === m 
                      ? 'bg-primary border-primary text-white shadow-lg shadow-primary/20' 
                      : 'bg-white border-slate-100 text-slate-400'
                  }`}
                >
                  {m}
                </button>
              ))}
            </div>
          </section>

          <section>
            <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-4">Features in Card</h3>
            <div className="grid grid-cols-2 gap-3">
              {Object.values(IPAFeature).map((feature) => {
                const isActive = settings.activeFeatures.includes(feature);
                return (
                  <button
                    key={feature}
                    onClick={() => toggleFeature(feature)}
                    className={`flex items-center justify-between p-3 rounded-2xl border-2 transition-all ${
                      isActive ? 'bg-primary/10 border-primary/20 text-primary' : 'bg-white border-slate-50 text-slate-300'
                    }`}
                  >
                    <span className="font-bold text-sm">{feature}</span>
                    {isActive && <Check className="w-4 h-4 text-primary" />}
                  </button>
                );
              })}
            </div>
          </section>

          <div className="grid grid-cols-2 gap-6">
            <section>
              <h3 className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-3 flex items-center gap-2">
                <Eye className="w-3 h-3 text-primary" /> Prompt
              </h3>
              <div className="flex flex-col gap-2">
                {settings.activeFeatures.map((f) => (
                  <button
                    key={f}
                    onClick={() => setPrompt(f)}
                    className={`p-2 rounded-xl border-2 text-xs font-bold transition-all ${
                      settings.promptFeature === f ? 'bg-primary/10 border-primary/20 text-primary' : 'bg-white border-slate-50 text-slate-300'
                    }`}
                  >
                    {f}
                  </button>
                ))}
              </div>
            </section>

            <section>
              <h3 className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-3 flex items-center gap-2">
                <EyeOff className="w-3 h-3 text-secondary" /> Answer
              </h3>
              <div className="flex flex-col gap-2">
                {settings.activeFeatures
                  .filter(f => f !== IPAFeature.SOUND)
                  .map((f) => (
                  <button
                    key={f}
                    onClick={() => setMasked(f)}
                    className={`p-2 rounded-xl border-2 text-xs font-bold transition-all ${
                      settings.maskedFeature === f ? 'bg-secondary/10 border-secondary/20 text-secondary' : 'bg-white border-slate-50 text-slate-300'
                    }`}
                  >
                    {f}
                  </button>
                ))}
              </div>
            </section>
          </div>

          <div className="pt-4 border-t border-slate-50 flex flex-col gap-4">
            <button 
              onClick={onReset}
              className="w-full py-4 border-2 border-slate-100 text-slate-400 rounded-2xl font-black text-sm flex items-center justify-center gap-2 hover:bg-slate-50"
            >
              <RotateCcw className="w-4 h-4" /> RESET ALL PROGRESS
            </button>
            <button 
              onClick={onClose}
              className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black text-lg hover:bg-slate-800 transition-all shadow-xl shadow-slate-200"
            >
              START STUDYING
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

const CACHE_NAME = 'ipa-master-v1';
const ASSETS = [
  '/',
  '/index.html',
  '/index.tsx',
  '/manifest.json',
  '/data/ipaData.ts',
  '/types.ts'
];

self.addEventListener('install', (event) => {
  event.waitUntil(
    caches.open(CACHE_NAME).then((cache) => cache.addAll(ASSETS))
  );
  self.skipWaiting();
});

self.addEventListener('activate', (event) => {
  event.waitUntil(self.clients.claim());
});

self.addEventListener('fetch', (event) => {
  // Stale-while-revalidate for assets, Network-first for audio
  if (event.request.url.includes('.mp3') || event.request.url.includes('googleSearch')) {
    event.respondWith(
      fetch(event.request).catch(() => caches.match(event.request))
    );
  } else {
    event.respondWith(
      caches.match(event.request).then((response) => {
        return response || fetch(event.request).then((networkResponse) => {
          return caches.open(CACHE_NAME).then((cache) => {
            cache.put(event.request, networkResponse.clone());
            return networkResponse;
          });
        });
      })
    );
  }
});

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { IPAFeature, IPACardData, AppSettings, CardState, LearningStatus } from './types';
import { ipaDataset } from './data/ipaData';
import { Flashcard } from './components/Flashcard';
import { FoldedCard } from './components/FoldedCard';
import { SettingsOverlay } from './components/SettingsOverlay';
import { Settings, Layers, Microscope, Music, MoveHorizontal, RotateCcw, ChevronLeft, ChevronRight, BookOpen, HandTap, CheckCircle2, Sliders } from 'lucide-react';
import { playIPASound, playSynthesizedWord } from './services/audioService';

const App: React.FC = () => {
  const [settings, setSettings] = useState<AppSettings>({
    activeFeatures: [IPAFeature.SYMBOL, IPAFeature.LABEL],
    promptFeature: IPAFeature.SYMBOL,
    maskedFeature: IPAFeature.LABEL,
    mode: 'FLASHCARD'
  });

  const [learnedMap, setLearnedMap] = useState<Record<string, LearningStatus>>(() => {
    const saved = localStorage.getItem('learned_map');
    return saved ? JSON.parse(saved) : {};
  });

  const [studyQueue, setStudyQueue] = useState<string[]>([]);
  const [deferredPrompt, setDeferredPrompt] = useState<any>(null);

  const [cardState, setCardState] = useState<CardState>({
    currentQueueIndex: 0,
    isFlipped: false,
    userInput: '',
    feedback: 'none'
  });

  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [activeTab, setActiveTab] = useState<'study' | 'lab' | 'tutorial'>('study');
  const [labInput, setLabInput] = useState('');

  const touchStart = useRef<number | null>(null);
  const touchEnd = useRef<number | null>(null);

  const triggerHaptic = (style: 'light' | 'medium' | 'success' | 'error' = 'light') => {
    if ('vibrate' in navigator) {
      if (style === 'success') navigator.vibrate([10, 30, 10]);
      else if (style === 'error') navigator.vibrate([50, 50, 50]);
      else navigator.vibrate(10);
    }
  };

  // Handle Android Back Button
  useEffect(() => {
    const handlePopState = (event: PopStateEvent) => {
      if (isSettingsOpen) {
        setIsSettingsOpen(false);
        window.history.pushState({ noBackExitsApp: true }, '');
      }
    };

    window.addEventListener('popstate', handlePopState);
    if (!window.history.state?.noBackExitsApp) {
      window.history.pushState({ noBackExitsApp: true }, '');
    }

    return () => window.removeEventListener('popstate', handlePopState);
  }, [isSettingsOpen]);

  // Handle PWA Installation
  useEffect(() => {
    const handler = (e: any) => {
      e.preventDefault();
      setDeferredPrompt(e);
    };
    window.addEventListener('beforeinstallprompt', handler);
    return () => window.removeEventListener('beforeinstallprompt', handler);
  }, []);

  const handleInstallClick = async () => {
    if (!deferredPrompt) return;
    deferredPrompt.prompt();
    const { outcome } = await deferredPrompt.userChoice;
    if (outcome === 'accepted') {
      setDeferredPrompt(null);
    }
  };

  // Initialize queue
  useEffect(() => {
    const freshQueue = ipaDataset
      .filter(card => learnedMap[card.id] !== LearningStatus.REMEMBERED)
      .map(card => card.id);

    if (freshQueue.length > 0) {
      freshQueue.sort(() => Math.random() - 0.5);
      setStudyQueue(freshQueue);
    } else {
      setStudyQueue([]);
    }
    setCardState(prev => ({ ...prev, currentQueueIndex: 0, isFlipped: false, userInput: '', feedback: 'none' }));
  }, [learnedMap, settings.mode]);

  useEffect(() => {
    localStorage.setItem('learned_map', JSON.stringify(learnedMap));
  }, [learnedMap]);

  const handleNext = useCallback(() => {
    if (studyQueue.length === 0) return;
    triggerHaptic();
    setCardState(prev => ({
      ...prev,
      currentQueueIndex: (prev.currentQueueIndex + 1) % studyQueue.length,
      isFlipped: false,
      userInput: '',
      feedback: 'none'
    }));
  }, [studyQueue]);

  const handlePrev = useCallback(() => {
    if (studyQueue.length === 0) return;
    triggerHaptic();
    setCardState(prev => ({
      ...prev,
      currentQueueIndex: (prev.currentQueueIndex - 1 + studyQueue.length) % studyQueue.length,
      isFlipped: false,
      userInput: '',
      feedback: 'none'
    }));
  }, [studyQueue]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.target instanceof HTMLInputElement) return;
      if (e.key === 'ArrowRight') handleNext();
      if (e.key === 'ArrowLeft') handlePrev();
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleNext, handlePrev]);

  const onTouchStart = (e: React.TouchEvent) => {
    touchEnd.current = null;
    touchStart.current = e.targetTouches[0].clientX;
  };

  const onTouchMove = (e: React.TouchEvent) => {
    touchEnd.current = e.targetTouches[0].clientX;
  };

  const onTouchEnd = () => {
    if (!touchStart.current || !touchEnd.current) return;
    const distance = touchStart.current - touchEnd.current;
    if (distance > 50) handleNext();
    if (distance < -50) handlePrev();
  };

  const currentCardId = studyQueue[cardState.currentQueueIndex];
  const currentCard = ipaDataset.find(c => c.id === currentCardId);

  const handleMarkStatus = (status: LearningStatus) => {
    if (!currentCard) return;
    triggerHaptic(status === LearningStatus.REMEMBERED ? 'success' : 'medium');
    if (status === LearningStatus.REMEMBERED) {
      setLearnedMap(prev => ({ ...prev, [currentCard.id]: LearningStatus.REMEMBERED }));
    } else {
      handleNext();
    }
  };

  const handleQuizSubmit = (input: string) => {
    if (!currentCard) return;
    const targetFeature = settings.maskedFeature;
    let isCorrect = false;

    const sanitizedInput = input.toLowerCase().trim();
    if (targetFeature === IPAFeature.SYMBOL) isCorrect = sanitizedInput === currentCard.symbol.toLowerCase();
    else if (targetFeature === IPAFeature.LABEL) isCorrect = currentCard.label.toLowerCase().includes(sanitizedInput);
    else if (targetFeature === IPAFeature.WORDS) isCorrect = currentCard.words.some(w => w.toLowerCase() === sanitizedInput);

    if (isCorrect) {
