    else if (targetFeature === IPAFeature.WORDS) isCorrect = currentCard.words.some(w => w.toLowerCase() === sanitizedInput);

    if (isCorrect) {
      triggerHaptic('success');
      setCardState(prev => ({ ...prev, feedback: 'correct', isFlipped: true }));
      setTimeout(() => {
        setLearnedMap(prev => ({ ...prev, [currentCard.id]: LearningStatus.REMEMBERED }));
      }, 1000);
    } else {
      triggerHaptic('error');
      setCardState(prev => ({ ...prev, feedback: 'incorrect', isFlipped: true }));
      setStudyQueue(prev => [...prev, currentCard.id]);
    }
  };

